import { createServer } from 'http';
import { parse } from 'url';
import next from 'next';
import { getSocketIO } from '@/lib/socket/server';
import { initializeChessGameHandlers } from '@/lib/games/chess/socket-handlers';
import { initializeTicTacToeHandlers } from '@/lib/games/tictactoe/socket-handlers';
import { initializeCheckersHandlers } from '@/lib/games/checkers/socket-handlers';
import { initializeConnect4Handlers } from '@/lib/games/connect4/socket-handlers';
import { initializePoolHandlers } from '@/lib/games/pool/socket-handlers';
import { initializeHexGLHandlers } from '@/lib/games/hexgl/socket-handlers';
import { initializeChkobeHandlers } from '@/lib/games/chkobe/socket-handlers';

const dev = process.env.NODE_ENV !== 'production';
const hostname = 'localhost';
const port = parseInt(process.env.PORT || '2500', 10);

const app = next({ dev, hostname, port });
const handle = app.getRequestHandler();

app.prepare().then(() => {
  const httpServer = createServer(async (req, res) => {
    try {
      const parsedUrl = parse(req.url!, true);
      await handle(req, res, parsedUrl);
    } catch (err) {
      console.error('Error occurred handling', req.url, err);
      res.statusCode = 500;
      res.end('internal server error');
    }
  });

  // Initialize Socket.IO
  const io = getSocketIO(httpServer);

  // Initialize game handlers
  initializeChessGameHandlers(io);
  initializeTicTacToeHandlers(io);
  initializeCheckersHandlers(io);
  initializeConnect4Handlers(io);
  initializePoolHandlers(io);
  initializeHexGLHandlers(io);
  initializeChkobeHandlers(io);

  httpServer
    .once('error', (err) => {
      console.error(err);
      process.exit(1);
    })
    .listen(port, () => {
      console.log(`> Ready on http://${hostname}:${port}`);
      console.log(`> Socket.IO ready on path: /api/socket/io`);
    });
});

