import { randomBytes, createHmac } from 'crypto';
import jwt from 'jsonwebtoken';
import { v4 as uuid } from 'uuid';
import { supabase } from './db';
import type {
  Tenant, GameSession, GameResult, SessionPlayer,
  GameType, SessionMode, MatchType, KeyType, SessionTokenPayload
} from './types';
import { GAME_TABLE } from './types';

const JWT_SECRET = process.env.GAAS_JWT_SECRET || 'dev_secret_change_me';
const SESSION_TTL = 60 * 5;

// ─── Key Generation ───────────────────────────────────────────────────────────

export function generateApiKey(type: KeyType): string {
  return `bg_${type}_` + randomBytes(24).toString('hex');
}

export function generateWebhookSecret(): string {
  return randomBytes(32).toString('hex');
}

/** 6-char uppercase room code for private matches */
function generateRoomCode(): string {
  return randomBytes(3).toString('hex').toUpperCase(); // e.g. "A3F9C1"
}

/** Anonymous player for training sessions — random adjective+noun style */
const ADJECTIVES = ['Swift','Bold','Calm','Dark','Keen','Wild','Wise','Brave','Sly','Grim'];
const NOUNS      = ['Fox','Wolf','Bear','Hawk','Lion','Crow','Lynx','Viper','Shark','Eagle'];
function generateAnonPlayer(): SessionPlayer {
  const adj  = ADJECTIVES[Math.floor(Math.random() * ADJECTIVES.length)];
  const noun = NOUNS[Math.floor(Math.random() * NOUNS.length)];
  const num  = Math.floor(Math.random() * 9000) + 1000;
  return { id: `anon_${uuid().slice(0, 8)}`, displayName: `${adj}${noun}${num}` };
}

// ─── Tenant ───────────────────────────────────────────────────────────────────

function rowToTenant(row: any): Tenant {
  return {
    id:             row.id,
    name:           row.name,
    email:          row.email,
    liveApiKey:     row.live_api_key,
    testApiKey:     row.test_api_key,
    webhookUrl:     row.webhook_url,
    webhookSecret:  row.webhook_secret,
    allowedOrigins: row.allowed_origins ?? [],
    theme:          row.theme ?? {},
    plan:           row.plan,
    isActive:       row.is_active,
    createdAt:      new Date(row.created_at),
  };
}

/** Resolve tenant + key type from any API key (live or test) */
export async function getTenantByApiKey(
  apiKey: string
): Promise<{ tenant: Tenant; keyType: KeyType } | null> {
  const isTest = apiKey.startsWith('bg_test_');
  const col    = isTest ? 'test_api_key' : 'live_api_key';

  const { data } = await supabase
    .from('tenants')
    .select('*')
    .eq(col, apiKey)
    .eq('is_active', true)
    .single();

  if (!data) return null;
  return { tenant: rowToTenant(data), keyType: isTest ? 'test' : 'live' };
}

export async function getTenantById(id: string): Promise<Tenant | null> {
  const { data } = await supabase.from('tenants').select('*').eq('id', id).single();
  return data ? rowToTenant(data) : null;
}

export async function createTenant(data: {
  name: string;
  email: string;
  allowedOrigins?: string[];
}): Promise<Tenant> {
  const id = uuid();
  const { error } = await supabase.from('tenants').insert({
    id,
    name:            data.name,
    email:           data.email,
    live_api_key:    generateApiKey('live'),
    test_api_key:    generateApiKey('test'),
    webhook_secret:  generateWebhookSecret(),
    allowed_origins: data.allowedOrigins ?? [],
    theme:           {},
    plan:            'starter',
    is_active:       true,
  });
  if (error) throw error;
  return (await getTenantById(id))!;
}

// ─── Origin Validation ────────────────────────────────────────────────────────

export function isOriginAllowed(tenant: Tenant, origin: string | null): boolean {
  if (!origin) return false;
  if (tenant.allowedOrigins.length === 0) return false;
  return tenant.allowedOrigins.some(allowed => {
    if (allowed === '*') return true;
    try { return new URL(origin).hostname === new URL(allowed).hostname; }
    catch { return false; }
  });
}

// ─── Test Session Store (in-memory, never persisted) ─────────────────────────
// Uses a global singleton so the API route and socket server share the same Map
// across Next.js module boundaries (each context gets its own module instance).

const g = globalThis as any;
if (!g.__bgTestSessions) g.__bgTestSessions = new Map<string, GameSession>();
const testSessions: Map<string, GameSession> = g.__bgTestSessions;

// ─── Session ──────────────────────────────────────────────────────────────────

function rowToSession(row: any, game: GameType): GameSession {
  return {
    id:        row.id,
    tenantId:  row.tenant_id,
    game,
    mode:      row.mode,
    matchType: row.match_type,
    roomCode:  row.room_code ?? undefined,
    players:   row.players,
    status:    row.status,
    result:    row.result ?? null,
    createdAt: new Date(row.created_at),
    endedAt:   row.ended_at ? new Date(row.ended_at) : null,
  };
}

export async function createSession(
  tenant: Tenant,
  game: GameType,
  players: SessionPlayer[],
  mode: SessionMode,
  matchType: MatchType = 'matchmaking',
  keyType: KeyType = 'live'
): Promise<{ session: GameSession; token: string }> {
  const id = uuid();

  const resolvedPlayers: SessionPlayer[] = mode === 'training'
    ? players.map(() => generateAnonPlayer())
    : players;

  const roomCode = matchType === 'private' ? generateRoomCode() : undefined;

  const session: GameSession = {
    id, tenantId: tenant.id, game, mode, matchType, roomCode,
    players: resolvedPlayers, status: 'pending', result: null,
    createdAt: new Date(), endedAt: null,
  };

  if (keyType === 'test') {
    testSessions.set(id, session);
  } else {
    const { error } = await supabase.from(GAME_TABLE[game]).insert({
      id, tenant_id: tenant.id, mode, match_type: matchType,
      room_code: roomCode ?? null, players: resolvedPlayers, status: 'pending',
    });
    if (error) throw error;
    await supabase.from('usage_events').insert({ tenant_id: tenant.id, session_id: id, game, mode });
  }

  const payload: Omit<SessionTokenPayload, 'iat'|'exp'> = {
    sessionId: id, tenantId: tenant.id, game, mode, matchType, roomCode, players: resolvedPlayers,
  };
  const token = jwt.sign(payload, JWT_SECRET, { expiresIn: SESSION_TTL });
  return { session, token };
}

export async function getSessionById(id: string, game: GameType): Promise<GameSession | null> {
  if (testSessions.has(id)) return testSessions.get(id)!;
  const { data } = await supabase.from(GAME_TABLE[game]).select('*').eq('id', id).single();
  return data ? rowToSession(data, game) : null;
}

export async function getPrivateSessionByRoomCode(
  roomCode: string,
  game: GameType,
  tenantId: string
): Promise<GameSession | null> {
  const code = roomCode.toUpperCase();
  // Check in-memory test sessions first
  for (const s of testSessions.values()) {
    if (s.roomCode === code && s.tenantId === tenantId && s.matchType === 'private' && s.status === 'pending')
      return s;
  }
  const { data } = await supabase
    .from(GAME_TABLE[game])
    .select('*')
    .eq('room_code', code)
    .eq('tenant_id', tenantId)
    .eq('match_type', 'private')
    .eq('status', 'pending')
    .single();
  return data ? rowToSession(data, game) : null;
}

export async function activateSession(sessionId: string, game: GameType): Promise<void> {
  if (testSessions.has(sessionId)) {
    testSessions.get(sessionId)!.status = 'active';
    return;
  }
  await supabase.from(GAME_TABLE[game])
    .update({ status: 'active' })
    .eq('id', sessionId)
    .eq('status', 'pending');
}

export async function endSession(sessionId: string, game: GameType, result: GameResult): Promise<void> {
  if (testSessions.has(sessionId)) {
    const s = testSessions.get(sessionId)!;
    s.status  = 'ended';
    s.result  = result;
    s.endedAt = new Date();
    // Keep in memory briefly so the client can read the result, then evict
    setTimeout(() => testSessions.delete(sessionId), 60_000);
    return;
  }

  const extra: any = {};
  if (game === 'chess' && result.pgn) extra.pgn = result.pgn;

  const { error } = await supabase.from(GAME_TABLE[game]).update({
    status: 'ended', result, ended_at: new Date().toISOString(), ...extra,
  }).eq('id', sessionId);

  if (error) {
    console.error(`[endSession] failed to end session ${sessionId} (${game}):`, error);
    throw error;
  }
}

export function verifySessionToken(token: string): SessionTokenPayload | null {
  try { return jwt.verify(token, JWT_SECRET) as SessionTokenPayload; }
  catch { return null; }
}

// ─── Tenant Isolation ─────────────────────────────────────────────────────────

/**
 * Matchmaking must respect tenant isolation:
 * - live:     only match players from the same tenant
 * - test:     only match players from the same tenant (no cross-tenant)
 * - training: cross-tenant pool — anyone can match anyone
 *
 * This is enforced in the GameStateManager by tagging each queue entry
 * with { tenantId, mode } and filtering accordingly.
 */
export function canPlayersMatch(
  a: { tenantId: string; mode: SessionMode },
  b: { tenantId: string; mode: SessionMode }
): boolean {
  if (a.mode !== b.mode) return false;                        // modes must match
  if (a.mode === 'training') return true;                     // training: cross-tenant OK
  return a.tenantId === b.tenantId;                           // live/test: same tenant only
}

// ─── Webhook (live mode only) ─────────────────────────────────────────────────

export function signWebhookPayload(secret: string, payload: string): string {
  return 'sha256=' + createHmac('sha256', secret).update(payload).digest('hex');
}

export async function deliverWebhook(
  tenant: Tenant,
  game: GameType,
  event: string,
  data: object
): Promise<void> {
  if (!tenant.webhookUrl) return;

  const deliveryId = uuid();
  const payload    = JSON.stringify({ event, deliveryId, data });
  const signature  = signWebhookPayload(tenant.webhookSecret, payload);

  await supabase.from('webhook_deliveries').insert({
    id:         deliveryId,
    tenant_id:  tenant.id,
    session_id: (data as any).sessionId || '',
    game,
    event,
    payload,
    status:     'pending',
  });

  const timeout = parseInt(process.env.GAAS_WEBHOOK_TIMEOUT_MS || '5000');

  const attempt = async (n: number) => {
    try {
      const ctrl = new AbortController();
      const t    = setTimeout(() => ctrl.abort(), timeout);
      const res  = await fetch(tenant.webhookUrl!, {
        method: 'POST',
        headers: {
          'Content-Type':          'application/json',
          'X-BetaGamer-Signature': signature,
          'X-BetaGamer-Event':     event,
          'X-BetaGamer-Delivery':  deliveryId,
        },
        body: payload, signal: ctrl.signal,
      });
      clearTimeout(t);

      await supabase.from('webhook_deliveries').update({
        status: res.ok ? 'delivered' : 'failed',
        attempts: n, last_attempt: new Date().toISOString(),
      }).eq('id', deliveryId);

      if (!res.ok && n < 3) setTimeout(() => attempt(n + 1), 1000 * 2 ** n);
    } catch {
      await supabase.from('webhook_deliveries').update({
        status: 'failed', attempts: n, last_attempt: new Date().toISOString(),
      }).eq('id', deliveryId);
      if (n < 3) setTimeout(() => attempt(n + 1), 1000 * 2 ** n);
    }
  };

  attempt(1);
}

