export type MatchType   = 'matchmaking' | 'private' | 'bot';
export type KeyType     = 'live' | 'test';

// Map game → supabase table name
export const GAME_TABLE: Record<GameType, string> = {
  'chess':         'sessions_chess',
  'checkers':      'sessions_checkers',
  'connect4':      'sessions_connect4',
  'tictactoe':     'sessions_tictactoe',
  'subway-runner': 'sessions_subway_runner',
  'pool':          'sessions_pool',
  'chkobe':        'sessions_chkobe',
};

export interface PartnerTheme {
  primaryColor?:    string;
  backgroundColor?: string;
  textColor?:       string;
  fontFamily?:      string;
  borderRadius?:    number;
  logo?:            string;
  gameName?:        string;
  hideAttribution?: boolean;
}

export interface Tenant {
  id:             string;
  name:           string;
  email:          string;
  liveApiKey:     string;
  testApiKey:     string;
  webhookUrl:     string | null;
  webhookSecret:  string;
