export interface GameResult {
  winner?:    string | null;   // player id, null = draw, undefined = no winner (runner)
  reason:     'checkmate' | 'resignation' | 'timeout' | 'disconnect' | 'draw' | 'collision' | 'game_over';
  duration:   number;          // seconds
  scores?:    Record<string, number>;
  pgn?:       string;          // chess only
  moveCount?: number;
  // subway-runner specific
