export type TrainingTrigger = 'manual' | 'auto' | 'pgn_import' | 'challenge';
export type BotGameType   = 'chess' | 'checkers' | 'connect4' | 'tictactoe';

export interface TenantBot {
  id:                 string;
  tenantId:           string;
  game:               BotGameType;
  name:               string;
  /** Player ID from the tenant's own user system — used as the bot's identity in games */
  playerId:           string;
  /** Display name shown to opponents in-game */
  displayName:        string;
  botType:            BotType;
  matchmakingWeight:  number;
  // algorithmic
  difficulty?:        BotDifficulty;
  // learned
  targetRating?:      BotRating;
