import { Server as SocketIOServer, Socket } from 'socket.io';
import { multiGameStateManager, Player } from '@/lib/game-engine-multi/GameStateManager';
import { registerMatchmakingHandlers } from '../shared/multi/matchmaking';
import { registerBaseHandlers } from '../shared/multi/socket-base';
import { startAfkTimer, clearAfkTimer } from '../shared/multi/afk-timers';
import { markSessionEnded } from '../shared/session';
import { ChkobeEngine, ChkobeGameState, Suit } from './ChkobeEngine';
import { CHKOBE_RULES } from './rules';
import { getBotMove } from './bot';

const GAME = 'chkobe';
const AFk_WARN_EVENT = 'chkobe:afk_warning';
const AFK_MS = 120_000;
const AFK_WARN_MS = 90_000;

interface ChkobeGameData {
  engine: ChkobeEngine;
  gameState: ChkobeGameState;
  sessionId?: string;
  afkTimeoutEnabled: boolean;
  // track who played second-to-last card without declaring check
  pendingCheckPenalty: string | null;
}

export const initializeChkobeHandlers = (io: SocketIOServer) => {
  const ns = io.of(`/${GAME}`);

  const emitGameOver = (roomId: string, winner: string | undefined, reason: string) => {
    clearAfkTimer(roomId);
    multiGameStateManager.endGame(roomId, winner);
    const room = multiGameStateManager.getRoom(roomId);
    const gd = room?.gameData as ChkobeGameData | undefined;
    ns.to(roomId).emit('game:over', {
      winner,
      winners: gd?.gameState.winners ?? [],
      reason,
    });
    markSessionEnded(roomId, GAME as any, winner, reason);
  };

  const onAfkForfeit = (roomId: string, loserId: string) => {
    const room = multiGameStateManager.getRoom(roomId);
    const winner = room?.players.find(p => p.id !== loserId)?.id;
    emitGameOver(roomId, winner, 'afk_timeout');
  };

  /** Execute bot turn if the current player is a bot (id starts with 'bot_') */
  const maybeBotTurn = (roomId: string) => {
    const room = multiGameStateManager.getRoom(roomId);
    if (!room || room.state !== 'playing') return;
    const gd = room.gameData as ChkobeGameData;
    if (gd.gameState.gameOver) return;

    const currentPlayer = gd.gameState.players[gd.gameState.currentTurn];
    if (!currentPlayer.id.startsWith('bot_')) return;

    setTimeout(() => {
      const freshRoom = multiGameStateManager.getRoom(roomId);
      if (!freshRoom || freshRoom.state !== 'playing') return;
      const freshGd = freshRoom.gameData as ChkobeGameData;
      if (freshGd.gameState.gameOver) return;

      const move = getBotMove(currentPlayer.id, freshGd.engine);

      if (move.action === 'draw') {
        const result = freshGd.engine.drawCards(currentPlayer.id);
        if (typeof result === 'string') return;
        freshGd.gameState = freshGd.engine.getState();
        multiGameStateManager.updateGameState(roomId, freshGd, { type: 'draw', playerId: currentPlayer.id });
        ns.to(roomId).emit('chkobe:drew', {
          playerId: currentPlayer.id,
          count: result.drawn.length,
          publicState: freshGd.engine.getPublicState(),
        });
      } else {
        const wasSecondToLast = freshGd.gameState.players.find(p => p.id === currentPlayer.id)!.hand.length === 2;
        const err = freshGd.engine.playCard(currentPlayer.id, move.cardId, move.declaredSuit);
        if (err) return;
        freshGd.gameState = freshGd.engine.getState();
        multiGameStateManager.updateGameState(roomId, freshGd, { type: 'play', cardId: move.cardId, playerId: currentPlayer.id });

        if (wasSecondToLast && CHKOBE_RULES.checkRequired && move.declareCheck) {
          freshGd.engine.declareCheck(currentPlayer.id);
          ns.to(roomId).emit('chkobe:check_declared', { playerId: currentPlayer.id });
        }

        ns.to(roomId).emit('chkobe:move', {
          playerId: currentPlayer.id,
          cardId: move.cardId,
          publicState: freshGd.engine.getPublicState(),
        });

        // Send each human player their updated hand
        freshGd.gameState.players.forEach((p, i) => {
          if (p.id.startsWith('bot_')) return;
          const s = freshRoom.players[i] ? ns.sockets.get(freshRoom.players[i].socketId) : null;
          s?.emit('chkobe:hand_update', { hand: p.hand });
        });

        if (freshGd.gameState.gameOver) {
          emitGameOver(roomId, freshGd.gameState.winners[0], 'victory');
          return;
        }
      }

      // Chain — next turn might also be a bot, otherwise restart AFK for human
      const nextPlayer = freshGd.gameState.players[freshGd.gameState.currentTurn];
      if (nextPlayer?.id.startsWith('bot_')) {
        maybeBotTurn(roomId);
      } else {
        clearAfkTimer(roomId);
        if (freshGd.afkTimeoutEnabled) {
          startAfkTimer(roomId, ns, AFk_WARN_EVENT, onAfkForfeit, { timeoutMs: AFK_MS, warnMs: AFK_WARN_MS });
        }
      }
    }, 800); // small delay so it feels natural
  };

  const startGame = ({ players, sockets, sessionId, afkTimeoutEnabled }: {
    players: Player[]; sockets: any[]; sessionId?: string; afkTimeoutEnabled: boolean;
  }) => {
    const room = multiGameStateManager.createRoom(GAME, players.length, players[0]);
    for (let i = 1; i < players.length; i++) multiGameStateManager.addPlayerToRoom(room.id, players[i]);

    const engine = new ChkobeEngine(CHKOBE_RULES, players.map(p => p.id));
    const gameState = engine.getState();

    const gd: ChkobeGameData = { engine, gameState, sessionId, afkTimeoutEnabled, pendingCheckPenalty: null };
    multiGameStateManager.updateGameState(room.id, gd);

    sockets.forEach((s, i) => {
      s?.join(room.id);
      s?.emit('game:started', {
        roomId: room.id,
        players: room.players,
        hand: gameState.players[i].hand,
        publicState: engine.getPublicState(players[i].id),
        rules: CHKOBE_RULES,
      });
    });

    if (sessionId) {
      import('../../gaas/service').then(({ activateSession }) => activateSession(sessionId, GAME as any)).catch(() => {});
    }

    if (afkTimeoutEnabled) {
      startAfkTimer(room.id, ns, AFk_WARN_EVENT, onAfkForfeit, { timeoutMs: AFK_MS, warnMs: AFK_WARN_MS });
    }

    // Trigger bot if it goes first
    maybeBotTurn(room.id);
  };

  ns.on('connection', (socket: Socket) => {
    console.log(`[${GAME}] connect ${socket.id}`);

    registerMatchmakingHandlers(socket, ns, GAME, CHKOBE_RULES.minPlayers, startGame);

    // ── Bot matchmaking override ───────────────────────────────────────────
    socket.on('matchmaking:join_bot', (data: {
      username: string; playerId?: string; sessionId?: string; afkTimeoutEnabled?: boolean;
    }) => {
      const { v4: uuidv4 } = require('uuid');
      const playerId = data.playerId || uuidv4();
      const human: Player = { id: playerId, socketId: socket.id, username: data.username, elo: 1200 };
      const bots: Player[] = Array.from({ length: CHKOBE_RULES.minPlayers - 1 }, (_, i) => ({
        id: `bot_${uuidv4()}`, socketId: 'bot', username: `Bot ${i + 1}`, elo: 1200, isBot: true,
      }));
      startGame({ players: [human, ...bots], sockets: [socket, ...bots.map(() => null)], sessionId: data.sessionId, afkTimeoutEnabled: data.afkTimeoutEnabled !== false });
    });

    // ── Play a card ────────────────────────────────────────────────────────
    socket.on('chkobe:play', (data: {
      roomId: string; playerId: string; cardId: string; declaredSuit?: Suit; declareCheck?: boolean;
    }) => {
      const room = multiGameStateManager.getRoom(data.roomId);
      if (!room || room.state !== 'playing') { socket.emit('error', { message: 'Game not in progress' }); return; }

      const gd = room.gameData as ChkobeGameData;
      const player = gd.gameState.players.find(p => p.id === data.playerId);
      if (!player) { socket.emit('error', { message: 'Player not found' }); return; }

      // Apply pending check penalty before the move if applicable
      if (gd.pendingCheckPenalty === data.playerId) {
        gd.engine.applyCheckPenalty(data.playerId);
        gd.pendingCheckPenalty = null;
        ns.to(data.roomId).emit('chkobe:check_penalty', { playerId: data.playerId });
      }

      const wasSecondToLast = player.hand.length === 2;

      const err = gd.engine.playCard(data.playerId, data.cardId, data.declaredSuit);
      if (err) { socket.emit('error', { message: err }); return; }

      gd.gameState = gd.engine.getState();
      multiGameStateManager.updateGameState(data.roomId, gd, { type: 'play', cardId: data.cardId, playerId: data.playerId });

      // Check penalty: played second-to-last without declaring check
      if (wasSecondToLast && CHKOBE_RULES.checkRequired) {
        if (data.declareCheck) {
          gd.engine.declareCheck(data.playerId);
          ns.to(data.roomId).emit('chkobe:check_declared', { playerId: data.playerId });
        } else {
          gd.pendingCheckPenalty = data.playerId;
        }
      }

      const updated = multiGameStateManager.getRoom(data.roomId);
      ns.to(data.roomId).emit('chkobe:move', {
        playerId: data.playerId,
        cardId: data.cardId,
        publicState: gd.engine.getPublicState(),
        currentTurn: updated?.currentTurn,
      });

      // Send each player their updated hand privately
      gd.gameState.players.forEach((p, i) => {
        const s = room.players[i] ? ns.sockets.get(room.players[i].socketId) : null;
        s?.emit('chkobe:hand_update', { hand: p.hand });
      });

      if (gd.gameState.gameOver) {
        emitGameOver(data.roomId, gd.gameState.winners[0], 'victory');
        return;
      }

      clearAfkTimer(data.roomId);
      if (gd.afkTimeoutEnabled) {
        startAfkTimer(data.roomId, ns, AFk_WARN_EVENT, onAfkForfeit, { timeoutMs: AFK_MS, warnMs: AFK_WARN_MS });
      }
      maybeBotTurn(data.roomId);
    });

    // ── Draw card(s) ───────────────────────────────────────────────────────
    socket.on('chkobe:draw', (data: { roomId: string; playerId: string }) => {
      const room = multiGameStateManager.getRoom(data.roomId);
      if (!room || room.state !== 'playing') { socket.emit('error', { message: 'Game not in progress' }); return; }

      const gd = room.gameData as ChkobeGameData;
      const result = gd.engine.drawCards(data.playerId);
      if (typeof result === 'string') { socket.emit('error', { message: result }); return; }

      gd.gameState = gd.engine.getState();
      multiGameStateManager.updateGameState(data.roomId, gd, { type: 'draw', playerId: data.playerId });

      const updated = multiGameStateManager.getRoom(data.roomId);
      ns.to(data.roomId).emit('chkobe:drew', {
        playerId: data.playerId,
        count: result.drawn.length,
        publicState: gd.engine.getPublicState(),
        currentTurn: updated?.currentTurn,
      });
      // Send drawn cards only to the drawing player
      socket.emit('chkobe:hand_update', { hand: gd.gameState.players.find(p => p.id === data.playerId)?.hand });

      clearAfkTimer(data.roomId);
      if (gd.afkTimeoutEnabled) {
        startAfkTimer(data.roomId, ns, AFk_WARN_EVENT, onAfkForfeit, { timeoutMs: AFK_MS, warnMs: AFK_WARN_MS });
      }
      maybeBotTurn(data.roomId);
    });

    registerBaseHandlers(socket, ns, GAME, emitGameOver, (_s, room) => {
      const gd = room.gameData as ChkobeGameData;
      const playerId = multiGameStateManager.getRoomBySocketId(_s.id)?.players.find(p => p.socketId === _s.id)?.id;
      return { hand: gd.gameState.players.find(p => p.id === playerId)?.hand ?? [] };
    });
  });
};

import { Socket } from 'socket.io';
import { v4 as uuidv4 } from 'uuid';
import { multiGameStateManager, Player, MatchmakingQueue } from '../../../game-engine-multi/GameStateManager';
import type { GameType } from '../../../gaas/types';

export interface StartGameOptions {
  players: Player[];          // all players including the one who triggered the match
  sockets: any[];             // socket instances in same order as players
  sessionId?: string;
  afkTimeoutEnabled: boolean;
}

function generateRoomCode(): string {
  return Math.random().toString(36).substring(2, 8).toUpperCase();
}

/**
 * Registers matchmaking:join, matchmaking:leave, private:create, private:join
 * for a multi-player game. Fires startGame once playerCount players are collected.
 */
export function registerMatchmakingHandlers(
  socket: Socket,
  namespace: any,
  game: string,
  playerCount: number,
  startGame: (opts: StartGameOptions) => void,
): void {

  // ── Private room: host creates ─────────────────────────────────────────
  socket.on('private:create', (data: {
    username: string; playerId?: string; elo?: number;
    afkTimeoutEnabled?: boolean; sessionId?: string;
  }) => {
    const playerId = data.playerId || uuidv4();
    const player: Player = { id: playerId, socketId: socket.id, username: data.username, elo: data.elo ?? 1200 };
    const roomCode = generateRoomCode();
    const room = multiGameStateManager.createPrivateRoom(game, playerCount, player, roomCode);
    socket.join(room.id);
    socket.emit('private:created', { roomId: room.id, roomCode, playerId });
  });

  // ── Private room: guest joins by code ──────────────────────────────────
  socket.on('private:join', (data: {
    username: string; playerId?: string; elo?: number;
    roomCode: string; afkTimeoutEnabled?: boolean; sessionId?: string;
  }) => {
    const room = multiGameStateManager.getRoomByCode(data.roomCode);
    if (!room) { socket.emit('error', { message: 'Room not found', code: 'ROOM_NOT_FOUND' }); return; }
    if (room.gameType !== game) { socket.emit('error', { message: 'Wrong game', code: 'WRONG_GAME' }); return; }
    if (room.state !== 'waiting') { socket.emit('error', { message: 'Room already started', code: 'ROOM_STARTED' }); return; }
    if (room.players.length >= room.playerCount) { socket.emit('error', { message: 'Room is full', code: 'ROOM_FULL' }); return; }

    const playerId = data.playerId || uuidv4();
    const player: Player = { id: playerId, socketId: socket.id, username: data.username, elo: data.elo ?? 1200 };
    multiGameStateManager.addPlayerToRoom(room.id, player);
    socket.join(room.id);

    // Notify host that someone joined
    namespace.to(room.id).emit('private:player_joined', { playerId, username: data.username, playerCount: room.players.length });

    if (room.players.length === room.playerCount) {
      // All players present — start
      const sockets = room.players.map(p => p.socketId === socket.id ? socket : namespace.sockets.get(p.socketId));
      startGame({ players: room.players, sockets, sessionId: data.sessionId, afkTimeoutEnabled: data.afkTimeoutEnabled !== false });
    }
  });

  socket.on('matchmaking:join', async (data: {
    username: string; playerId?: string; elo?: number;
    afkTimeoutEnabled?: boolean; sessionId?: string;
  }) => {
    const playerId          = data.playerId || uuidv4();
    const elo               = data.elo || 1200;
    const afkTimeoutEnabled = data.afkTimeoutEnabled !== false;

    if (data.sessionId) {
      try {
        const { getSessionById } = await import('../../../gaas/service');
        const session = await getSessionById(data.sessionId, game as GameType);
        if (session?.status === 'ended')  { socket.emit('error', { message: 'Session already ended',  code: 'SESSION_ENDED'  }); return; }
        if (session?.status === 'active') { socket.emit('error', { message: 'Session already active', code: 'SESSION_ACTIVE' }); return; }
      } catch {}
    }

    multiGameStateManager.addToMatchmaking({
      playerId, socketId: socket.id, username: data.username, elo,
      gameType: game, playerCount, timestamp: Date.now(),
    });

    const matched = multiGameStateManager.findMatch(game, playerId);
    if (matched) {
      // Resolve sockets for all matched players
      const allEntries = [
        { playerId, socketId: socket.id, username: data.username, elo },
        ...matched.map((m: MatchmakingQueue) => ({ playerId: m.playerId, socketId: m.socketId, username: m.username, elo: m.elo })),
      ];

      const sockets = allEntries.map(e => e.socketId === socket.id ? socket : namespace.sockets.get(e.socketId));

      // If any socket is stale, re-queue everyone
      if (sockets.some(s => !s)) {
        allEntries.forEach(e => {
          if (!namespace.sockets.get(e.socketId)) {
            multiGameStateManager.removeFromMatchmaking(e.playerId, game);
          }
        });
        multiGameStateManager.addToMatchmaking({ playerId, socketId: socket.id, username: data.username, elo, gameType: game, playerCount, timestamp: Date.now() });
        socket.emit('matchmaking:waiting', { playerId, position: multiGameStateManager.getQueuePosition(playerId, game) });
        return;
      }

      const players: Player[] = allEntries.map(e => ({ id: e.playerId, socketId: e.socketId, username: e.username, elo: e.elo }));
      startGame({ players, sockets, sessionId: data.sessionId, afkTimeoutEnabled });
    } else {
      socket.emit('matchmaking:waiting', { playerId, position: multiGameStateManager.getQueuePosition(playerId, game) });
    }
  });

  socket.on('matchmaking:leave', (data: { playerId: string }) => {
    const existingRoom = multiGameStateManager.getRoomByPlayerId(data.playerId);
    if (existingRoom?.state === 'playing') { socket.emit('matchmaking:already_started', { roomId: existingRoom.id }); return; }
    multiGameStateManager.removeFromMatchmaking(data.playerId, game);
    socket.emit('matchmaking:left');
  });
}

export type WinCondition = 'first_empty' | 'last_standing' | 'weighted_score';

export interface SpecialCardRule {
  action: 'draw' | 'skip' | 'change_suit';
  amount?: number;
  wild?: boolean;
  stackable?: boolean;
  stackableWith?: string[];
  counters?: string[];   // nullifies pending pickup
  passers?: string[];    // redirects pickup to next player without adding
}

export interface ChkobeRules {
  maxPlayers: number;
  minPlayers: number;
  deck: 'standard52+jokers';
  initialHandSize: number;
  drawOnNoMatch: number;
  allowPickupStacking: boolean;
  checkRequired: boolean;
  checkPenalty: number;
  winCondition: WinCondition;
  cardWeights: Record<string, number>;
  specialCards: Record<string, SpecialCardRule>;
  suitRules: { JOKER_RED: string[]; JOKER_BLACK: string[] };
  matchRules: { canMatchByRank: boolean; canMatchBySuit: boolean };
  wildRanks?: string[]; // ranks playable on any card regardless of suit/rank
}

export const CHKOBE_RULES: ChkobeRules = {
  maxPlayers: 8,
  minPlayers: 4,
  deck: 'standard52+jokers',
  initialHandSize: 7,
  drawOnNoMatch: 1,
  allowPickupStacking: true,
  checkRequired: true,
  checkPenalty: 1,
  winCondition: 'first_empty',
  cardWeights: {
    JOKER: 40, A: 11, K: 2, Q: 3, J: 20, '10': 10, '2': 2, default: 1,
  },
  specialCards: {
    '7': {
      action: 'draw',
      amount: 2,
      stackable: false,
      // stackableWith: ['7', 'JOKER'],
      // counters: ['J'], 
      // passers: ['A'],
    },
    A: { action: 'skip' },
    J: { action: 'change_suit' },
    JOKER: {
      action: 'draw',
      amount: 4,
      wild: true, // can be played on any card
      stackable: false,
      // stackableWith: ['JOKER', '7'],
      // counters: ['J'],
    },
  },
  suitRules: {
    JOKER_RED:   ['hearts', 'diamonds'],
    JOKER_BLACK: ['spades', 'clubs'],
  },
  matchRules: { canMatchByRank: true, canMatchBySuit: true },
  wildRanks: ['J'],
};

/**
 * Multi-player game state manager.
 * Supports 2–N players per room. Turn rotates (currentTurn + 1) % playerCount.
 * Parallel to game-engine/GameStateManager — existing 1v1 games are untouched.
 */

import { v4 as uuidv4 } from 'uuid';

export interface Player {
  id: string;
  socketId: string;
  username: string;
  elo?: number;
  isBot?: boolean;
  difficulty?: 'easy' | 'medium' | 'hard';
  botId?: string;
  /** Player's color/token in the game (e.g. 'red', 'blue', 'green', 'yellow' for Ludo) */
  color?: string;
}

export interface GameRoom {
  id: string;
  gameType: string;
  /** How many players needed before the game starts */
  playerCount: number;
  players: Player[];
  spectators: Player[];
  state: 'waiting' | 'playing' | 'paused' | 'finished';
  currentTurn: number;
  gameData: any;
  createdAt: number;
  lastMoveAt: number;
  winner?: string;
  moveHistory: any[];
  /** Set for private rooms — players join by this code */
  roomCode?: string;
}

export interface MatchmakingQueue {
  playerId: string;
  socketId: string;
  username: string;
  elo: number;
  gameType: string;
  playerCount: number;
  timestamp: number;
  tenantId?: string;
  sessionMode?: 'live' | 'test' | 'training';
  sessionId?: string;
}

class MultiGameStateManager {
  private rooms           = new Map<string, GameRoom>();
  private playerRooms     = new Map<string, string>();
  private socketToPlayer  = new Map<string, string>();
  private matchmakingQueue = new Map<string, MatchmakingQueue[]>();
  private disconnectedPlayers = new Map<string, { roomId: string; timeout: ReturnType<typeof setTimeout> }>();
  private privateRooms    = new Map<string, string>(); // roomCode → roomId

  // ─── Room lifecycle ────────────────────────────────────────────────────────

  createRoom(gameType: string, playerCount: number, firstPlayer: Player): GameRoom {
    const room: GameRoom = {
      id: uuidv4(), gameType, playerCount,
      players: [firstPlayer], spectators: [],
      state: 'waiting', currentTurn: 0,
      gameData: {}, createdAt: Date.now(), lastMoveAt: Date.now(), moveHistory: [],
    };
    this.rooms.set(room.id, room);
    this.playerRooms.set(firstPlayer.id, room.id);
    this.socketToPlayer.set(firstPlayer.socketId, firstPlayer.id);
    return room;
  }

  createPrivateRoom(gameType: string, playerCount: number, firstPlayer: Player, roomCode: string): GameRoom {
    const room = this.createRoom(gameType, playerCount, firstPlayer);
    room.roomCode = roomCode.toUpperCase();
    this.privateRooms.set(room.roomCode, room.id);
    return room;
  }

  getRoomByCode(roomCode: string): GameRoom | undefined {
    const roomId = this.privateRooms.get(roomCode.toUpperCase());
    return roomId ? this.rooms.get(roomId) : undefined;
  }

  getRoom(roomId: string)                { return this.rooms.get(roomId); }
  getRoomByPlayerId(playerId: string)    { const id = this.playerRooms.get(playerId); return id ? this.rooms.get(id) : undefined; }
  getRoomBySocketId(socketId: string)    { const pid = this.socketToPlayer.get(socketId); return pid ? this.getRoomByPlayerId(pid) : undefined; }

  addPlayerToRoom(roomId: string, player: Player): boolean {
    const room = this.rooms.get(roomId);
    if (!room || room.players.length >= room.playerCount) return false;
    room.players.push(player);
    this.playerRooms.set(player.id, roomId);
    this.socketToPlayer.set(player.socketId, player.id);
    if (room.players.length === room.playerCount) {
      room.state = 'playing';
      room.lastMoveAt = Date.now();
    }
    return true;
  }

  addSpectator(roomId: string, spectator: Player): boolean {
    const room = this.rooms.get(roomId);
    if (!room) return false;
    room.spectators.push(spectator);
    this.socketToPlayer.set(spectator.socketId, spectator.id);
    return true;
  }

  updateGameState(roomId: string, gameData: any, moveData?: any): void {
    const room = this.rooms.get(roomId);
    if (!room) return;
    room.gameData = gameData;
    room.lastMoveAt = Date.now();
    if (moveData) room.moveHistory.push({ ...moveData, timestamp: Date.now() });
  }

  switchTurn(roomId: string): void {
    const room = this.rooms.get(roomId);
    if (!room) return;
    room.currentTurn = (room.currentTurn + 1) % room.players.length;
  }

  /** Skip to a specific player's turn (e.g. after a 6 in Ludo grants another roll) */
  setTurn(roomId: string, playerIndex: number): void {
    const room = this.rooms.get(roomId);
    if (!room) return;
    room.currentTurn = playerIndex % room.players.length;
  }

  endGame(roomId: string, winner?: string): void {
    const room = this.rooms.get(roomId);
    if (!room) return;
    room.state = 'finished';
    room.winner = winner;
    // Clear AFK timer to prevent stale forfeit firing after game ends
    const { clearAfkTimer } = require('../games/shared/multi/afk-timers');
    clearAfkTimer(roomId);
    setTimeout(() => this.deleteRoom(roomId), 5_000);
  }

  deleteRoom(roomId: string): void {
    const room = this.rooms.get(roomId);
    if (!room) return;
    [...room.players, ...room.spectators].forEach(p => {
      this.playerRooms.delete(p.id);
      this.socketToPlayer.delete(p.socketId);
    });
    if (room.roomCode) this.privateRooms.delete(room.roomCode);
    this.rooms.delete(roomId);
  }

  // ─── Matchmaking ───────────────────────────────────────────────────────────

  addToMatchmaking(entry: MatchmakingQueue): void {
    const queue = this.matchmakingQueue.get(entry.gameType) ?? [];
    const idx = queue.findIndex(q => q.playerId === entry.playerId);
    if (idx !== -1) queue.splice(idx, 1);
    queue.push(entry);
    this.matchmakingQueue.set(entry.gameType, queue);
  }

  removeFromMatchmaking(playerId: string, gameType: string): void {
    const queue = this.matchmakingQueue.get(gameType) ?? [];
    this.matchmakingQueue.set(gameType, queue.filter(q => q.playerId !== playerId));
  }

  removeFromMatchmakingBySocketId(socketId: string): void {
    for (const [gameType, queue] of this.matchmakingQueue.entries()) {
      this.matchmakingQueue.set(gameType, queue.filter(q => q.socketId !== socketId));
    }
  }

  getQueueEntryBySocketId(socketId: string): MatchmakingQueue | null {
    for (const queue of this.matchmakingQueue.values()) {
      const entry = queue.find(q => q.socketId === socketId);
      if (entry) return entry;
    }
    return null;
  }

  getQueuePosition(playerId: string, gameType: string): number {
    return (this.matchmakingQueue.get(gameType) ?? []).findIndex(q => q.playerId === playerId);
  }

  /**
   * Collects `playerCount - 1` opponents for the given player.
   * Returns the matched players if enough are found, null otherwise.
   * Removes all matched players from the queue.
   */
  findMatch(gameType: string, playerId: string): MatchmakingQueue[] | null {
    const queue = this.matchmakingQueue.get(gameType) ?? [];
    const player = queue.find(q => q.playerId === playerId);
    if (!player) return null;

    const needed = player.playerCount - 1;

    const candidates = queue.filter(q => {
      if (q.playerId === playerId) return false;
      if (q.playerCount !== player.playerCount) return false;
      if (Math.abs(q.elo - player.elo) > 300) return false;
      const sameMode = q.sessionMode === player.sessionMode;
      if (!sameMode) return false;
      if (player.sessionMode === 'training') return true;
      if (player.tenantId && q.tenantId) return player.tenantId === q.tenantId;
      return true;
    });

    if (candidates.length < needed) return null;

    // Pick closest ELO matches
    const matched = candidates
      .sort((a, b) => Math.abs(a.elo - player.elo) - Math.abs(b.elo - player.elo))
      .slice(0, needed);

    [playerId, ...matched.map(m => m.playerId)].forEach(id => this.removeFromMatchmaking(id, gameType));
    return matched;
  }

  // ─── Reconnection ──────────────────────────────────────────────────────────

  handleDisconnect(socketId: string, reconnectWindow = 60_000): void {
    const playerId = this.socketToPlayer.get(socketId);
    if (!playerId) return;
    const roomId = this.playerRooms.get(playerId);
    if (!roomId) return;
    const room = this.rooms.get(roomId);
    if (!room || room.state === 'finished') return;
    if (room.state === 'playing') room.state = 'paused';
    const timeout = setTimeout(() => this.handlePlayerQuit(playerId), reconnectWindow);
    this.disconnectedPlayers.set(playerId, { roomId, timeout });
  }

  handleReconnect(playerId: string, newSocketId: string): boolean {
    const disconnectData = this.disconnectedPlayers.get(playerId);
    if (disconnectData) { clearTimeout(disconnectData.timeout); this.disconnectedPlayers.delete(playerId); }
    const roomId = disconnectData?.roomId ?? this.playerRooms.get(playerId);
    if (!roomId) return false;
    const room = this.rooms.get(roomId);
    if (!room || room.state === 'finished') return false;
    const player = room.players.find(p => p.id === playerId);
    if (!player) return false;
    this.socketToPlayer.delete(player.socketId);
    player.socketId = newSocketId;
    this.socketToPlayer.set(newSocketId, playerId);
    if (room.state === 'paused') room.state = 'playing';
    return true;
  }

  handlePlayerQuit(playerId: string): void {
    const roomId = this.playerRooms.get(playerId);
    if (!roomId) return;
    const room = this.rooms.get(roomId);
    if (!room) return;
    if (room.state === 'playing' || room.state === 'paused') {
      // With 2+ players still active, game can continue — remove the quitter
      room.players = room.players.filter(p => p.id !== playerId);
      this.playerRooms.delete(playerId);
      if (room.players.length === 1) {
        this.endGame(roomId, room.players[0].id);
      } else if (room.players.length === 0) {
        this.deleteRoom(roomId);
      } else {
        // Adjust currentTurn if needed
        room.currentTurn = room.currentTurn % room.players.length;
        room.state = 'playing';
      }
    } else {
      this.deleteRoom(roomId);
    }
  }
}

