// ─── Lobby (pre-game waiting room for variable player count games) ─────────────

export interface Lobby {
  id: string;
  gameType: string;
  minPlayers: number;
  maxPlayers: number;
  entries: MatchmakingQueue[];
  timer: ReturnType<typeof setTimeout> | null;
  waitMs: number;
}

class MultiGameStateManager {
  private rooms           = new Map<string, GameRoom>();
  private playerRooms     = new Map<string, string>();
  private socketToPlayer  = new Map<string, string>();
  private matchmakingQueue = new Map<string, MatchmakingQueue[]>();
  private disconnectedPlayers = new Map<string, { roomId: string; timeout: ReturnType<typeof setTimeout> }>();
  private privateRooms    = new Map<string, string>(); // roomCode → roomId
  private lobbies         = new Map<string, Lobby>();  // gameType → current open lobby
  private playerLobby     = new Map<string, string>(); // playerId → lobbyId

// ─── Lobby ────────────────────────────────────────────────────────────────

getOrCreateLobby(gameType: string, minPlayers: number, maxPlayers: number, waitMs: number): Lobby {
  const existing = this.lobbies.get(gameType);
  if (existing) return existing;
  const lobby: Lobby = { id: uuidv4(), gameType, minPlayers, maxPlayers, entries: [], timer: null, waitMs };
  this.lobbies.set(gameType, lobby);
  return lobby;
}

getLobby(gameType: string): Lobby | undefined {
  return this.lobbies.get(gameType);
}

addToLobby(gameType: string, entry: MatchmakingQueue): void {
  const lobby = this.lobbies.get(gameType);
  if (!lobby) return;
  if (!lobby.entries.find(e => e.playerId === entry.playerId)) {
    lobby.entries.push(entry);
    this.playerLobby.set(entry.playerId, lobby.id);
  }
}

removeFromLobby(playerId: string, gameType: string): void {
  const lobby = this.lobbies.get(gameType);
  if (!lobby) return;
  lobby.entries = lobby.entries.filter(e => e.playerId !== playerId);
  this.playerLobby.delete(playerId);
}

dissolveLobby(gameType: string): void {
  const lobby = this.lobbies.get(gameType);
  if (!lobby) return;
  if (lobby.timer) clearTimeout(lobby.timer);
  lobby.entries.forEach(e => this.playerLobby.delete(e.playerId));
  this.lobbies.delete(gameType);
}

/** Pops all entries from the lobby and deletes it so a new one can form */
flushLobby(gameType: string): MatchmakingQueue[] {
  const lobby = this.lobbies.get(gameType);
  if (!lobby) return [];
  if (lobby.timer) clearTimeout(lobby.timer);
  const entries = [...lobby.entries];
  entries.forEach(e => this.playerLobby.delete(e.playerId));
  this.lobbies.delete(gameType);
  return entries;
}

// ─── Reconnection ──────────────────────────────────────────────────────────

import { Socket } from 'socket.io';
import { v4 as uuidv4 } from 'uuid';
import { multiGameStateManager, Player, MatchmakingQueue } from '../../../game-engine-multi/GameStateManager';
import type { GameType } from '../../../gaas/types';

export interface StartGameOptions {
  players: Player[];
  sockets: any[];
  sessionId?: string;
  afkTimeoutEnabled: boolean;
}

function generateRoomCode(): string {
  return Math.random().toString(36).substring(2, 8).toUpperCase();
}

const LOBBY_WAIT_MS = 30_000;

/**
 * Registers matchmaking:join, matchmaking:leave, private:create, private:join.
 * - Fixed count (min === max): start immediately when count is met.
 * - Variable count (min < max): lobby + countdown model.
 */
export function registerMatchmakingHandlers(
  socket: Socket,
  namespace: any,
  game: string,
  playerCount: number,
  startGame: (opts: StartGameOptions) => void,
  minPlayers?: number,
): void {
  const isVariable = minPlayers !== undefined && minPlayers < playerCount;

  // ── Lobby helpers (variable count only) ───────────────────────────────
  const scheduleLobbyCheck = (gameType: string) => {
    const lobby = multiGameStateManager.getLobby(gameType);
    if (!lobby) return;
    if (lobby.timer) clearTimeout(lobby.timer);
    lobby.timer = setTimeout(() => attemptLobbyStart(gameType), lobby.waitMs);
  };

  const attemptLobbyStart = (gameType: string) => {
    const lobby = multiGameStateManager.getLobby(gameType);
    if (!lobby) return;

    if (lobby.entries.length >= lobby.minPlayers) {
      // Take up to maxPlayers and start
      const toStart = lobby.entries.slice(0, lobby.maxPlayers);
      // Flush lobby so new players form a fresh one
      multiGameStateManager.flushLobby(gameType);

      const sockets = toStart.map(e =>
        e.socketId === socket.id ? socket : namespace.sockets.get(e.socketId)
      );

      // Drop stale sockets
      const valid = toStart.filter((_, i) => !!sockets[i]);
      const validSockets = sockets.filter(Boolean);

      if (valid.length >= lobby.minPlayers) {
        const players: Player[] = valid.map(e => ({ id: e.playerId, socketId: e.socketId, username: e.username, elo: e.elo }));
        startGame({ players, sockets: validSockets, afkTimeoutEnabled: true });
      } else {
        // Not enough valid sockets — notify and dissolve
        toStart.forEach(e => {
          const s = namespace.sockets.get(e.socketId);
          s?.emit('matchmaking:cancelled', { reason: 'not_enough_players' });
        });
      }
    } else if (lobby.entries.length === 0) {
      multiGameStateManager.dissolveLobby(gameType);
    } else {
      // Extend — notify players and reschedule
      lobby.entries.forEach(e => {
        const s = namespace.sockets.get(e.socketId);
        s?.emit('matchmaking:waiting', {
          playerId: e.playerId,
          playerCount: lobby.entries.length,
          minPlayers: lobby.minPlayers,
          maxPlayers: lobby.maxPlayers,
          extending: true,
        });
      });
      scheduleLobbyCheck(gameType);
    }
  };

  // ── Private room: host creates ─────────────────────────────────────────
  socket.on('private:create', (data: {
    username: string; playerId?: string; elo?: number;
    afkTimeoutEnabled?: boolean; sessionId?: string;
  }) => {
    const playerId = data.playerId || uuidv4();
    const player: Player = { id: playerId, socketId: socket.id, username: data.username, elo: data.elo ?? 1200 };
    const roomCode = generateRoomCode();
    const room = multiGameStateManager.createPrivateRoom(game, playerCount, player, roomCode);
    socket.join(room.id);
    socket.emit('private:created', { roomId: room.id, roomCode, playerId });
  });

  // ── Private room: guest joins by code ──────────────────────────────────
  socket.on('private:join', (data: {
    username: string; playerId?: string; elo?: number;
    roomCode: string; afkTimeoutEnabled?: boolean; sessionId?: string;
  }) => {
    const room = multiGameStateManager.getRoomByCode(data.roomCode);
    if (!room) { socket.emit('error', { message: 'Room not found', code: 'ROOM_NOT_FOUND' }); return; }
    if (room.gameType !== game) { socket.emit('error', { message: 'Wrong game', code: 'WRONG_GAME' }); return; }
    if (room.state !== 'waiting') { socket.emit('error', { message: 'Room already started', code: 'ROOM_STARTED' }); return; }
    if (room.players.length >= room.playerCount) { socket.emit('error', { message: 'Room is full', code: 'ROOM_FULL' }); return; }

    const playerId = data.playerId || uuidv4();
    const player: Player = { id: playerId, socketId: socket.id, username: data.username, elo: data.elo ?? 1200 };
    multiGameStateManager.addPlayerToRoom(room.id, player);
    socket.join(room.id);

    namespace.to(room.id).emit('private:player_joined', { playerId, username: data.username, playerCount: room.players.length });

    if (room.players.length === room.playerCount) {
      const sockets = room.players.map(p => p.socketId === socket.id ? socket : namespace.sockets.get(p.socketId));
      startGame({ players: room.players, sockets, sessionId: data.sessionId, afkTimeoutEnabled: data.afkTimeoutEnabled !== false });
    }
  });

  socket.on('matchmaking:join', async (data: {
    username: string; playerId?: string; elo?: number;
    afkTimeoutEnabled?: boolean; sessionId?: string;
  }) => {
    const playerId          = data.playerId || uuidv4();
    const elo               = data.elo || 1200;
    const afkTimeoutEnabled = data.afkTimeoutEnabled !== false;

    if (data.sessionId) {
      try {
        const { getSessionById } = await import('../../../gaas/service');
        const session = await getSessionById(data.sessionId, game as GameType);
        if (session?.status === 'ended')  { socket.emit('error', { message: 'Session already ended',  code: 'SESSION_ENDED'  }); return; }
        if (session?.status === 'active') { socket.emit('error', { message: 'Session already active', code: 'SESSION_ACTIVE' }); return; }
      } catch {}
    }

    // ── Variable count: lobby model ──────────────────────────────────────
    if (isVariable) {
      const lobby = multiGameStateManager.getOrCreateLobby(game, minPlayers!, playerCount, LOBBY_WAIT_MS);
      const entry: MatchmakingQueue = {
        playerId, socketId: socket.id, username: data.username, elo,
        gameType: game, playerCount, timestamp: Date.now(),
      };
      multiGameStateManager.addToLobby(game, entry);

      // Start timer on first player
      if (lobby.entries.length === 1) scheduleLobbyCheck(game);

      // Hit max — start immediately
      if (lobby.entries.length >= lobby.maxPlayers) {
        attemptLobbyStart(game);
        return;
      }

      socket.emit('matchmaking:waiting', {
        playerId,
        playerCount: lobby.entries.length,
        minPlayers: lobby.minPlayers,
        maxPlayers: lobby.maxPlayers,
      });
      return;
    }

    // ── Fixed count: original immediate-match logic ──────────────────────
    multiGameStateManager.addToMatchmaking({
      playerId, socketId: socket.id, username: data.username, elo,
      gameType: game, playerCount, timestamp: Date.now(),
    });

    const matched = multiGameStateManager.findMatch(game, playerId);
    if (matched) {
      const allEntries = [
        { playerId, socketId: socket.id, username: data.username, elo },
        ...matched.map((m: MatchmakingQueue) => ({ playerId: m.playerId, socketId: m.socketId, username: m.username, elo: m.elo })),
      ];

      const sockets = allEntries.map(e => e.socketId === socket.id ? socket : namespace.sockets.get(e.socketId));

      if (sockets.some(s => !s)) {
        allEntries.forEach(e => {
          if (!namespace.sockets.get(e.socketId)) multiGameStateManager.removeFromMatchmaking(e.playerId, game);
        });
        multiGameStateManager.addToMatchmaking({ playerId, socketId: socket.id, username: data.username, elo, gameType: game, playerCount, timestamp: Date.now() });
        socket.emit('matchmaking:waiting', { playerId, position: multiGameStateManager.getQueuePosition(playerId, game) });
        return;
      }

      const players: Player[] = allEntries.map(e => ({ id: e.playerId, socketId: e.socketId, username: e.username, elo: e.elo }));
      startGame({ players, sockets, sessionId: data.sessionId, afkTimeoutEnabled });
    } else {
      socket.emit('matchmaking:waiting', { playerId, position: multiGameStateManager.getQueuePosition(playerId, game) });
    }
  });

  socket.on('matchmaking:leave', (data: { playerId: string }) => {
    const existingRoom = multiGameStateManager.getRoomByPlayerId(data.playerId);
    if (existingRoom?.state === 'playing') { socket.emit('matchmaking:already_started', { roomId: existingRoom.id }); return; }

    if (isVariable) {
      multiGameStateManager.removeFromLobby(data.playerId, game);
      const lobby = multiGameStateManager.getLobby(game);
      if (lobby?.entries.length === 0) multiGameStateManager.dissolveLobby(game);
    } else {
      multiGameStateManager.removeFromMatchmaking(data.playerId, game);
    }
    socket.emit('matchmaking:left');
  });
}

