export interface TargetRing {
  label: string;
  /** Normalised radius 0–1 (1 = outer edge of target board) */
  radiusNorm: number;
  points: number;
  color: string;
}

export interface ArcheryRules {
  minPlayers: number;
  maxPlayers: number;
  sets: number;
  arrowsPerSet: number;
  /** Distance from archer to target in metres (visual scale only) */
  targetDistance: number;
  /** 0 = no wind. Max random wind speed in m/s applied as arrow drift */
  maxWindSpeed: number;
  /** Whether wind direction changes each set */
  windChangesPerSet: boolean;
  /** Hand tremor amplitude 0–1 (0 = none) */
  tremorAmplitude: number;
  /** Rings from innermost (bullseye) to outermost */
  rings: TargetRing[];
  /** Miss = arrow lands outside all rings */
  missPenalty: number;
}

export const ARCHERY_RULES: ArcheryRules = {
  minPlayers: 2,
  maxPlayers: 8,
  sets: 2,
  arrowsPerSet: 3,
  targetDistance: 70,
  maxWindSpeed: 5,       // 0 disables wind entirely
  windChangesPerSet: true,
  tremorAmplitude: 0.04, // 0 disables tremor
  missPenalty: 0,
  rings: [
    { label: 'X',      radiusNorm: 0.06, points: 10, color: '#FFD700' }, // inner gold
    { label: '10',     radiusNorm: 0.12, points: 10, color: '#FFD700' },
    { label: '9',      radiusNorm: 0.20, points:  9, color: '#FF4444' },
    { label: '8',      radiusNorm: 0.28, points:  8, color: '#FF4444' },
    { label: '7',      radiusNorm: 0.38, points:  7, color: '#4488FF' },
    { label: '6',      radiusNorm: 0.48, points:  6, color: '#4488FF' },
    { label: '5',      radiusNorm: 0.58, points:  5, color: '#111111' },
    { label: '4',      radiusNorm: 0.68, points:  4, color: '#111111' },
    { label: '3',      radiusNorm: 0.78, points:  3, color: '#FFFFFF' },
    { label: '2',      radiusNorm: 0.88, points:  2, color: '#FFFFFF' },
    { label: '1',      radiusNorm: 1.00, points:  1, color: '#FFFFFF' },
  ],
};

import { ArcheryRules } from './rules';

export interface Vec2 { x: number; y: number; }

export interface ArrowShot {
  /** Normalised hit position on target face (-1 to 1 on each axis) */
  hitNorm: Vec2;
  points: number;
  ringLabel: string;
  miss: boolean;
}

export interface PlayerSetScore {
  playerId: string;
  shots: ArrowShot[];
  setTotal: number;
}

export interface ArcheryGameState {
  players: string[];           // player IDs in turn order
  currentPlayerIndex: number;
  currentSet: number;          // 1-based
  arrowsFiredThisSet: number;
  /** wind vector for current set, magnitude in m/s */
  wind: Vec2;
  scores: Record<string, PlayerSetScore[]>; // playerId → per-set scores
  gameOver: boolean;
  winners: string[];           // sorted by total score desc
}

export class ArcheryEngine {
  private rules: ArcheryRules;
  private state: ArcheryGameState;

  constructor(rules: ArcheryRules, playerIds: string[]) {
    this.rules = rules;
    this.state = {
      players: [...playerIds],
      currentPlayerIndex: 0,
      currentSet: 1,
      arrowsFiredThisSet: 0,
      wind: this.generateWind(),
      scores: Object.fromEntries(playerIds.map(id => [id, []])),
      gameOver: false,
      winners: [],
    };
    // Initialise first set score entry for each player
    playerIds.forEach(id => this.state.scores[id].push({ playerId: id, shots: [], setTotal: 0 }));
  }

  private generateWind(): Vec2 {
    const max = this.rules.maxWindSpeed;
    if (max === 0) return { x: 0, y: 0 };
    const angle = Math.random() * Math.PI * 2;
    const speed = Math.random() * max;
    return { x: Math.cos(angle) * speed, y: Math.sin(angle) * speed };
  }

  getState(): ArcheryGameState {
    return JSON.parse(JSON.stringify(this.state));
  }

  /**
   * Record a shot for the current player.
   * @param aimNorm  Normalised aim point (-1..1 on each axis) — raw from client before server-side physics
   * @param power    0–1 pull power
   * @returns ArrowShot or error string
   */
  shoot(playerId: string, aimNorm: Vec2, power: number): ArrowShot | string {
    if (this.state.gameOver) return 'Game is over';
    const currentId = this.state.players[this.state.currentPlayerIndex];
    if (playerId !== currentId) return 'Not your turn';

    // Apply wind drift (scaled by distance and inverse power — harder pull = less drift)
    const windScale = (this.rules.targetDistance / 70) * (1 - power * 0.4) * 0.012;
    const hit: Vec2 = {
      x: aimNorm.x + this.state.wind.x * windScale,
      y: aimNorm.y + this.state.wind.y * windScale,
    };

    // Clamp to [-1.5, 1.5] — beyond 1.0 norm radius = miss
    hit.x = Math.max(-1.5, Math.min(1.5, hit.x));
    hit.y = Math.max(-1.5, Math.min(1.5, hit.y));

    const dist = Math.sqrt(hit.x * hit.x + hit.y * hit.y);
    const miss = dist > 1.0;

    let points = this.rules.missPenalty;
    let ringLabel = 'M';

    if (!miss) {
      const ring = this.rules.rings.find(r => dist <= r.radiusNorm);
      if (ring) { points = ring.points; ringLabel = ring.label; }
    }

    const shot: ArrowShot = { hitNorm: hit, points, ringLabel, miss };

    const setIdx = this.state.currentSet - 1;
    const playerSet = this.state.scores[playerId][setIdx];
    playerSet.shots.push(shot);
    playerSet.setTotal += points;

    this.state.arrowsFiredThisSet++;

    // Advance turn
    this.advanceTurn();

    return shot;
  }

  private advanceTurn(): void {
    const { players, arrowsPerSet, sets } = { ...this.rules, players: this.state.players };
    const totalArrowsThisSet = arrowsPerSet * players.length;

    if (this.state.arrowsFiredThisSet >= totalArrowsThisSet) {
      // Set complete
      if (this.state.currentSet >= sets) {
        this.state.gameOver = true;
        this.state.winners = this.computeWinners();
        return;
      }
      // Next set
      this.state.currentSet++;
      this.state.arrowsFiredThisSet = 0;
      this.state.currentPlayerIndex = 0;
      if (this.rules.windChangesPerSet) this.state.wind = this.generateWind();
      players.forEach(id => this.state.scores[id].push({ playerId: id, shots: [], setTotal: 0 }));
    } else {
      this.state.currentPlayerIndex = (this.state.currentPlayerIndex + 1) % players.length;
    }
  }

  private computeWinners(): string[] {
    const totals = this.state.players.map(id => ({
      id,
      total: this.state.scores[id].reduce((s, set) => s + set.setTotal, 0),
    }));
    totals.sort((a, b) => b.total - a.total);
    const top = totals[0].total;
    return totals.filter(t => t.total === top).map(t => t.id);
  }

  getTotals(): Record<string, number> {
    return Object.fromEntries(
      this.state.players.map(id => [
        id,
        this.state.scores[id].reduce((s, set) => s + set.setTotal, 0),
      ])
    );
  }
}

import { Server as SocketIOServer, Socket } from 'socket.io';
import { multiGameStateManager, Player } from '@/lib/game-engine-multi/GameStateManager';
import { registerMatchmakingHandlers } from '../shared/multi/matchmaking';
import { registerBaseHandlers } from '../shared/multi/socket-base';
import { startAfkTimer, clearAfkTimer } from '../shared/multi/afk-timers';
import { markSessionEnded } from '../shared/session';
import { ArcheryEngine, Vec2 } from './ArcheryEngine';
import { ARCHERY_RULES } from './rules';

const GAME = 'archery';
const AFK_WARN_EVENT = 'archery:afk_warning';
const AFK_MS = 60_000;
const AFK_WARN_MS = 45_000;

interface ArcheryGameData {
  engine: ArcheryEngine;
  sessionId?: string;
  afkTimeoutEnabled: boolean;
}

export const initializeArcheryHandlers = (io: SocketIOServer) => {
  const ns = io.of(`/${GAME}`);

  const emitGameOver = (roomId: string, winner: string | undefined, reason: string) => {
    clearAfkTimer(roomId);
    multiGameStateManager.endGame(roomId, winner);
    const room = multiGameStateManager.getRoom(roomId);
    const gd = room?.gameData as ArcheryGameData | undefined;
    const engine = gd?.engine;
    ns.to(roomId).emit('game:over', {
      winner,
      winners: engine ? engine.getState().winners : [],
      totals: engine ? engine.getTotals() : {},
      reason,
    });
    markSessionEnded(roomId, GAME as any, winner, reason);
  };

  const onAfkForfeit = (roomId: string, loserId: string) => {
    const room = multiGameStateManager.getRoom(roomId);
    const winner = room?.players.find(p => p.id !== loserId)?.id;
    emitGameOver(roomId, winner, 'afk_timeout');
  };

  const startGame = ({ players, sockets, sessionId, afkTimeoutEnabled }: {
    players: Player[]; sockets: any[]; sessionId?: string; afkTimeoutEnabled: boolean;
  }) => {
    const room = multiGameStateManager.createRoom(GAME, players.length, players[0]);
    for (let i = 1; i < players.length; i++) multiGameStateManager.addPlayerToRoom(room.id, players[i]);

    const engine = new ArcheryEngine(ARCHERY_RULES, players.map(p => p.id));
    const state = engine.getState();

    const gd: ArcheryGameData = { engine, sessionId, afkTimeoutEnabled };
    multiGameStateManager.updateGameState(room.id, gd);

    sockets.forEach(s => s?.join(room.id));
    ns.to(room.id).emit('game:started', {
      roomId: room.id,
      players: room.players,
      state,
      rules: ARCHERY_RULES,
    });

    if (sessionId) {
      import('../../gaas/service').then(({ activateSession }) => activateSession(sessionId, GAME as any)).catch(() => {});
    }

    if (afkTimeoutEnabled) {
      startAfkTimer(room.id, ns, AFK_WARN_EVENT, onAfkForfeit, { timeoutMs: AFK_MS, warnMs: AFK_WARN_MS });
    }
  };

  ns.on('connection', (socket: Socket) => {
    console.log(`[${GAME}] connect ${socket.id}`);

    registerMatchmakingHandlers(socket, ns, GAME, ARCHERY_RULES.maxPlayers, startGame, ARCHERY_RULES.minPlayers);

    // ── Bot match ──────────────────────────────────────────────────────────
    socket.on('matchmaking:join_bot', (data: {
      username: string; playerId?: string; sessionId?: string; afkTimeoutEnabled?: boolean;
    }) => {
      const { v4: uuidv4 } = require('uuid');
      const playerId = data.playerId || uuidv4();
      const human: Player = { id: playerId, socketId: socket.id, username: data.username, elo: 1200 };
      const bot: Player = { id: `bot_${uuidv4()}`, socketId: 'bot', username: 'Bot', elo: 1200, isBot: true };
      startGame({ players: [human, bot], sockets: [socket, null], sessionId: data.sessionId, afkTimeoutEnabled: data.afkTimeoutEnabled !== false });
    });

    // ── Shoot ──────────────────────────────────────────────────────────────
    socket.on('archery:shoot', (data: { roomId: string; playerId: string; aimNorm: Vec2; power: number }) => {
      const room = multiGameStateManager.getRoom(data.roomId);
      if (!room || room.state !== 'playing') { socket.emit('error', { message: 'Game not in progress' }); return; }

      const gd = room.gameData as ArcheryGameData;
      const result = gd.engine.shoot(data.playerId, data.aimNorm, data.power);

      if (typeof result === 'string') { socket.emit('error', { message: result }); return; }

      const state = gd.engine.getState();
      multiGameStateManager.updateGameState(data.roomId, gd, { type: 'shoot', playerId: data.playerId });

      ns.to(data.roomId).emit('archery:shot', {
        playerId: data.playerId,
        shot: result,
        state,
        totals: gd.engine.getTotals(),
      });

      if (state.gameOver) {
        emitGameOver(data.roomId, state.winners[0], 'game_over');
        return;
      }

      clearAfkTimer(data.roomId);
      if (gd.afkTimeoutEnabled) {
        startAfkTimer(data.roomId, ns, AFK_WARN_EVENT, onAfkForfeit, { timeoutMs: AFK_MS, warnMs: AFK_WARN_MS });
      }
    });

    registerBaseHandlers(socket, ns, GAME, emitGameOver, () => ({}));
  });
};

