'use client';

import { useState } from 'react';
import { useRouter } from 'next/navigation';
import Link from 'next/link';

export default function ArcheryLobbyPage() {
  const router = useRouter();
  const [username, setUsername] = useState('');
  const [mode, setMode] = useState<'matchmaking' | 'bot'>('matchmaking');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handlePlay = async () => {
    if (!username.trim()) return;
    setLoading(true); setError('');
    try {
      const res = await fetch('/api/v1/sessions', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${(window as any).__BG_TEST_KEY__ || 'bg_live_f631bc9ff5a1a8c533c123e3e2292bedb349241b5beaae1a'}`,
        },
        body: JSON.stringify({
          game: 'archery',
          mode: 'live',
          matchType: mode === 'bot' ? 'bot' : 'matchmaking',
          players: [{ id: `user_${Date.now()}`, displayName: username }],
        }),
      });
      if (!res.ok) { const e = await res.json(); throw new Error(e.error || 'Failed'); }
      const { sessionId, sessionToken } = await res.json();
      router.push(`/games/archery/${sessionId}?token=${sessionToken}&username=${encodeURIComponent(username)}&mode=${mode}`);
    } catch (e: any) {
      setError(e.message);
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-[#0a0f0a] text-white flex flex-col">
      <div className="border-b border-slate-800 px-6 py-4 flex items-center gap-4">
        <Link href="/games" className="text-slate-400 hover:text-white text-sm transition-colors">← Games</Link>
        <span className="text-slate-600">|</span>
        <span className="text-white font-semibold">🏹 Archery</span>
      </div>

      <div className="flex-1 flex items-center justify-center px-4">
        <div className="w-full max-w-sm">
          <div className="text-center mb-8">
            <div className="text-6xl mb-4">🏹</div>
            <h1 className="text-3xl font-bold mb-2">Archery</h1>
            <p className="text-slate-400 text-sm">3D turn-based multiplayer</p>
          </div>

          <div className="bg-slate-900 border border-slate-800 rounded-2xl p-6 space-y-4">
            <div>
              <label className="block text-xs text-slate-400 mb-1.5">Your name</label>
              <input value={username} onChange={e => setUsername(e.target.value)}
                onKeyDown={e => e.key === 'Enter' && handlePlay()} placeholder="Enter your name"
                className="w-full bg-slate-800 border border-slate-700 rounded-lg px-3 py-2.5 text-white text-sm placeholder-slate-600 focus:outline-none focus:border-green-500 transition-colors" />
            </div>

            <div>
              <label className="block text-xs text-slate-400 mb-1.5">Mode</label>
              <div className="grid grid-cols-2 gap-2">
                {(['matchmaking', 'bot'] as const).map(m => (
                  <button key={m} onClick={() => setMode(m)}
                    className={`py-2.5 rounded-lg text-sm font-medium transition-colors ${mode === m ? 'bg-green-700 text-white' : 'bg-slate-800 text-slate-400 hover:text-white border border-slate-700'}`}>
                    {m === 'matchmaking' ? '🌍 Online' : '🤖 vs Bot'}
                  </button>
                ))}
              </div>
            </div>

            {error && <p className="text-red-400 text-xs">{error}</p>}

            <button onClick={handlePlay} disabled={!username.trim() || loading}
              className="w-full py-3 bg-green-700 hover:bg-green-600 disabled:opacity-40 disabled:cursor-not-allowed text-white font-bold rounded-lg transition-colors">
              {loading ? 'Creating session…' : 'Play'}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

'use client';

import { useEffect, useRef, useState, useCallback } from 'react';
import * as THREE from 'three';
import { ARCHERY_RULES, TargetRing } from '@/lib/games/archery/rules';
import type { ArcheryGameState, ArrowShot, Vec2 } from '@/lib/games/archery/ArcheryEngine';

// ─── Types ────────────────────────────────────────────────────────────────────

interface ShotResult {
  playerId: string;
  shot: ArrowShot;
  state: ArcheryGameState;
  totals: Record<string, number>;
}

interface PlayerInfo { id: string; username: string; }

interface Props {
  socket: any;
  roomId: string;
  playerId: string;
  players: PlayerInfo[];
  initialState: ArcheryGameState;
}

// ─── Constants ────────────────────────────────────────────────────────────────

const TARGET_Z = -40;
const TARGET_RADIUS = 3.5;
const BOW_PULL_MAX = 2.2;   // world units
const ARROW_SPEED = 80;
const PARTICLE_COUNT = 120;

// ─── Scene builder ────────────────────────────────────────────────────────────

function buildScene(canvas: HTMLCanvasElement) {
  const renderer = new THREE.WebGLRenderer({ canvas, antialias: true, alpha: false });
  renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
  renderer.shadowMap.enabled = true;
  renderer.shadowMap.type = THREE.PCFSoftShadowMap;
  renderer.toneMapping = THREE.ACESFilmicToneMapping;
  renderer.toneMappingExposure = 1.1;

  const scene = new THREE.Scene();
  scene.background = new THREE.Color(0x0a1a0a);
  scene.fog = new THREE.FogExp2(0x0a1a0a, 0.018);

  const camera = new THREE.PerspectiveCamera(65, canvas.clientWidth / canvas.clientHeight, 0.1, 300);
  camera.position.set(0, 1.6, 0);
  camera.lookAt(0, 1.6, TARGET_Z);

  // ── Lighting ──────────────────────────────────────────────────────────────
  const ambient = new THREE.AmbientLight(0x334433, 0.6);
  scene.add(ambient);

  const sun = new THREE.DirectionalLight(0xfff5cc, 1.4);
  sun.position.set(10, 20, -10);
  sun.castShadow = true;
  sun.shadow.mapSize.set(2048, 2048);
  sun.shadow.camera.far = 120;
  sun.shadow.camera.left = -30;
  sun.shadow.camera.right = 30;
  sun.shadow.camera.top = 20;
  sun.shadow.camera.bottom = -5;
  scene.add(sun);

  const fill = new THREE.HemisphereLight(0x88aaff, 0x224422, 0.4);
  scene.add(fill);

  // ── Ground ────────────────────────────────────────────────────────────────
  const groundGeo = new THREE.PlaneGeometry(80, 120);
  const groundMat = new THREE.MeshLambertMaterial({ color: 0x1a3a1a });
  const ground = new THREE.Mesh(groundGeo, groundMat);
  ground.rotation.x = -Math.PI / 2;
  ground.position.y = -0.01;
  ground.receiveShadow = true;
  scene.add(ground);

  // ── Grass tufts (instanced) ───────────────────────────────────────────────
  const tuftGeo = new THREE.ConeGeometry(0.04, 0.25, 4);
  const tuftMat = new THREE.MeshLambertMaterial({ color: 0x2d5a2d });
  const tuftCount = 600;
  const tuftMesh = new THREE.InstancedMesh(tuftGeo, tuftMat, tuftCount);
  const dummy = new THREE.Object3D();
  for (let i = 0; i < tuftCount; i++) {
    dummy.position.set((Math.random() - 0.5) * 70, 0.12, (Math.random() - 0.5) * 110 - 5);
    dummy.rotation.y = Math.random() * Math.PI;
    dummy.scale.setScalar(0.8 + Math.random() * 0.6);
    dummy.updateMatrix();
    tuftMesh.setMatrixAt(i, dummy.matrix);
  }
  scene.add(tuftMesh);

  // ── Trees (simple) ────────────────────────────────────────────────────────
  const trunkGeo = new THREE.CylinderGeometry(0.12, 0.18, 2.5, 6);
  const trunkMat = new THREE.MeshLambertMaterial({ color: 0x4a3020 });
  const leafGeo  = new THREE.SphereGeometry(1.1, 6, 5);
  const leafMat  = new THREE.MeshLambertMaterial({ color: 0x1e5c1e });
  const treePositions = [
    [-8, -15], [8, -12], [-10, -25], [9, -28], [-7, -38], [10, -42],
    [-12, -5], [11, -8], [-9, -50], [8, -55],
  ];
  treePositions.forEach(([x, z]) => {
    const trunk = new THREE.Mesh(trunkGeo, trunkMat);
    trunk.position.set(x, 1.25, z);
    trunk.castShadow = true;
    scene.add(trunk);
    const leaves = new THREE.Mesh(leafGeo, leafMat);
    leaves.position.set(x, 3.2, z);
    leaves.castShadow = true;
    scene.add(leaves);
  });

  // ── Target board ──────────────────────────────────────────────────────────
  const targetGroup = new THREE.Group();
  targetGroup.position.set(0, 1.6, TARGET_Z);

  // Backing board
  const boardGeo = new THREE.BoxGeometry(TARGET_RADIUS * 2.4, TARGET_RADIUS * 2.4, 0.15);
  const boardMat = new THREE.MeshLambertMaterial({ color: 0x8b6914 });
  const board = new THREE.Mesh(boardGeo, boardMat);
  board.receiveShadow = true;
  targetGroup.add(board);

  // Rings (back to front, largest first)
  const sortedRings = [...ARCHERY_RULES.rings].reverse();
  sortedRings.forEach((ring, i) => {
    const geo = new THREE.CircleGeometry(ring.radiusNorm * TARGET_RADIUS, 64);
    const mat = new THREE.MeshLambertMaterial({ color: new THREE.Color(ring.color), side: THREE.FrontSide });
    const mesh = new THREE.Mesh(geo, mat);
    mesh.position.z = 0.08 + i * 0.001;
    targetGroup.add(mesh);
  });

  // Post
  const postGeo = new THREE.CylinderGeometry(0.06, 0.08, 1.6, 8);
  const postMat = new THREE.MeshLambertMaterial({ color: 0x5a4010 });
  const post = new THREE.Mesh(postGeo, postMat);
  post.position.set(0, -TARGET_RADIUS * 1.2 - 0.8, 0);
  post.castShadow = true;
  targetGroup.add(post);

  scene.add(targetGroup);

  // ── Bow (first-person, stays in camera space) ─────────────────────────────
  const bowGroup = new THREE.Group();

  // Limbs
  const limbGeo = new THREE.CylinderGeometry(0.018, 0.012, 0.9, 6);
  const limbMat = new THREE.MeshLambertMaterial({ color: 0x6b3a1f });
  const topLimb = new THREE.Mesh(limbGeo, limbMat);
  topLimb.position.set(0, 0.45, 0);
  topLimb.rotation.z = 0.12;
  bowGroup.add(topLimb);
  const botLimb = new THREE.Mesh(limbGeo, limbMat);
  botLimb.position.set(0, -0.45, 0);
  botLimb.rotation.z = -0.12;
  bowGroup.add(botLimb);

  // String
  const stringMat = new THREE.LineBasicMaterial({ color: 0xddddcc });
  const stringPoints = [new THREE.Vector3(0.06, 0.82, 0), new THREE.Vector3(0, 0, 0), new THREE.Vector3(0.06, -0.82, 0)];
  const stringGeo = new THREE.BufferGeometry().setFromPoints(stringPoints);
  const bowString = new THREE.Line(stringGeo, stringMat);
  bowGroup.add(bowString);

  // Arrow on bow
  const arrowShaftGeo = new THREE.CylinderGeometry(0.008, 0.008, 0.7, 6);
  const arrowMat = new THREE.MeshLambertMaterial({ color: 0xc8a060 });
  const arrowOnBow = new THREE.Mesh(arrowShaftGeo, arrowMat);
  arrowOnBow.rotation.x = Math.PI / 2;
  arrowOnBow.position.set(0, 0, -0.35);
  bowGroup.add(arrowOnBow);

  bowGroup.position.set(0.28, -0.22, -0.55);
  camera.add(bowGroup);
  scene.add(camera);

  // ── Wind particles ────────────────────────────────────────────────────────
  const particleGeo = new THREE.BufferGeometry();
  const positions = new Float32Array(PARTICLE_COUNT * 3);
  for (let i = 0; i < PARTICLE_COUNT; i++) {
    positions[i * 3]     = (Math.random() - 0.5) * 20;
    positions[i * 3 + 1] = Math.random() * 4;
    positions[i * 3 + 2] = (Math.random() - 0.5) * 60 - 10;
  }
  particleGeo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
  const particleMat = new THREE.PointsMaterial({ color: 0xaaffaa, size: 0.04, transparent: true, opacity: 0.35 });
  const particles = new THREE.Points(particleGeo, particleMat);
  scene.add(particles);

  return { renderer, scene, camera, bowGroup, bowString, arrowOnBow, particles, targetGroup };
}

// ─── Arrow flight animation ───────────────────────────────────────────────────

function createFlyingArrow(scene: THREE.Scene): THREE.Group {
  const g = new THREE.Group();
  const shaft = new THREE.Mesh(
    new THREE.CylinderGeometry(0.008, 0.008, 0.7, 6),
    new THREE.MeshLambertMaterial({ color: 0xc8a060 })
  );
  shaft.rotation.x = Math.PI / 2;
  g.add(shaft);
  const tip = new THREE.Mesh(
    new THREE.ConeGeometry(0.015, 0.06, 6),
    new THREE.MeshLambertMaterial({ color: 0x888888 })
  );
  tip.rotation.x = Math.PI / 2;
  tip.position.z = -0.38;
  g.add(tip);
  scene.add(g);
  return g;
}

// ─── Hit marker ───────────────────────────────────────────────────────────────

function createHitMarker(scene: THREE.Scene, hitNorm: Vec2): THREE.Mesh {
  const geo = new THREE.CircleGeometry(0.06, 12);
  const mat = new THREE.MeshBasicMaterial({ color: 0xffffff, transparent: true, opacity: 0.9 });
  const mesh = new THREE.Mesh(geo, mat);
  mesh.position.set(
    hitNorm.x * TARGET_RADIUS,
    hitNorm.y * TARGET_RADIUS,
    TARGET_Z + 0.12
  );
  scene.add(mesh);
  return mesh;
}

// ─── Main component ───────────────────────────────────────────────────────────

export default function ArcheryScene({ socket, roomId, playerId, players, initialState }: Props) {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const sceneRef  = useRef<ReturnType<typeof buildScene> | null>(null);
  const stateRef  = useRef<ArcheryGameState>(initialState);
  const pullRef   = useRef(0);          // 0–1 pull amount
  const isPulling = useRef(false);
  const pullStart = useRef<{ x: number; y: number } | null>(null);
  const aimRef    = useRef<Vec2>({ x: 0, y: 0 });
  const hitMarkersRef = useRef<THREE.Mesh[]>([]);
  const animFrameRef  = useRef<number>(0);

  const [gameState, setGameState] = useState<ArcheryGameState>(initialState);
  const [lastShot, setLastShot]   = useState<ShotResult | null>(null);
  const [totals, setTotals]       = useState<Record<string, number>>(
    Object.fromEntries(players.map(p => [p.id, 0]))
  );
  const [gameOver, setGameOver]   = useState(false);
  const [winners, setWinners]     = useState<string[]>([]);

  const isMyTurn = useCallback(() => {
    const s = stateRef.current;
    return !s.gameOver && s.players[s.currentPlayerIndex] === playerId;
  }, [playerId]);

  // ── Socket events ──────────────────────────────────────────────────────────
  useEffect(() => {
    socket.on('archery:shot', (data: ShotResult) => {
      stateRef.current = data.state;
      setGameState(data.state);
      setLastShot(data);
      setTotals(data.totals);

      // Place hit marker on target
      if (sceneRef.current) {
        const marker = createHitMarker(sceneRef.current.scene, data.shot.hitNorm);
        hitMarkersRef.current.push(marker);
      }
    });

    socket.on('game:over', (data: { winners: string[]; totals: Record<string, number> }) => {
      setGameOver(true);
      setWinners(data.winners);
      if (data.totals) setTotals(data.totals);
    });

    return () => { socket.off('archery:shot'); socket.off('game:over'); };
  }, [socket]);

  // ── Three.js setup ─────────────────────────────────────────────────────────
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const s = buildScene(canvas);
    sceneRef.current = s;

    const resize = () => {
      const w = canvas.clientWidth, h = canvas.clientHeight;
      s.renderer.setSize(w, h, false);
      s.camera.aspect = w / h;
      s.camera.updateProjectionMatrix();
    };
    resize();
    window.addEventListener('resize', resize);

    let t = 0;
    const animate = () => {
      animFrameRef.current = requestAnimationFrame(animate);
      t += 0.016;

      // Animate wind particles
      const pos = s.particles.geometry.attributes.position as THREE.BufferAttribute;
      const wind = stateRef.current.wind;
      for (let i = 0; i < PARTICLE_COUNT; i++) {
        pos.array[i * 3]     += (wind.x * 0.012 + 0.005);
        pos.array[i * 3 + 2] += 0.04;
        if (pos.array[i * 3 + 2] > 2) pos.array[i * 3 + 2] = -60;
        if (pos.array[i * 3] > 10)    pos.array[i * 3] = -10;
      }
      pos.needsUpdate = true;

      // Subtle tree sway
      s.scene.children.forEach(child => {
        if (child instanceof THREE.Mesh && child.geometry instanceof THREE.SphereGeometry) {
          child.rotation.z = Math.sin(t * 0.8 + child.position.x) * 0.03;
        }
      });

      // Bow pull visual — string bends back
      if (isPulling.current && pullRef.current > 0) {
        const pull = pullRef.current * BOW_PULL_MAX;
        const pts = s.bowString.geometry.attributes.position as THREE.BufferAttribute;
        pts.setXYZ(1, pull * 0.18, 0, pull * 0.12);
        pts.needsUpdate = true;
        s.arrowOnBow.position.z = -0.35 + pull * 0.08;
      }

      // Aim sway (tremor)
      if (isMyTurn() && ARCHERY_RULES.tremorAmplitude > 0) {
        const amp = ARCHERY_RULES.tremorAmplitude * (1 - pullRef.current * 0.5);
        s.camera.rotation.x = (aimRef.current.y * 0.08) + Math.sin(t * 3.1) * amp * 0.5;
        s.camera.rotation.y = (-aimRef.current.x * 0.08) + Math.sin(t * 2.7 + 1) * amp;
      }

      s.renderer.render(s.scene, s.camera);
    };
    animate();

    return () => {
      cancelAnimationFrame(animFrameRef.current);
      window.removeEventListener('resize', resize);
      s.renderer.dispose();
    };
  }, [isMyTurn]);

  // ── Input handlers ─────────────────────────────────────────────────────────
  const onPointerDown = useCallback((e: React.PointerEvent) => {
    if (!isMyTurn()) return;
    isPulling.current = true;
    pullStart.current = { x: e.clientX, y: e.clientY };
  }, [isMyTurn]);

  const onPointerMove = useCallback((e: React.PointerEvent) => {
    if (!isPulling.current || !pullStart.current) return;
    const dx = (e.clientX - pullStart.current.x) / window.innerWidth;
    const dy = (e.clientY - pullStart.current.y) / window.innerHeight;
    // Drag left/up = pull back
    pullRef.current = Math.min(1, Math.max(0, -dx * 3));
    aimRef.current = { x: dx * 4, y: -dy * 4 };
  }, []);

  const onPointerUp = useCallback(() => {
    if (!isPulling.current || !isMyTurn()) return;
    isPulling.current = false;

    const power = pullRef.current;
    if (power < 0.05) { pullRef.current = 0; return; } // accidental tap

    // Reset string visual
    if (sceneRef.current) {
      const pts = sceneRef.current.bowString.geometry.attributes.position as THREE.BufferAttribute;
      pts.setXYZ(1, 0, 0, 0);
      pts.needsUpdate = true;
      sceneRef.current.arrowOnBow.position.z = -0.35;

      // Animate arrow flying
      const arrow = createFlyingArrow(sceneRef.current.scene);
      arrow.position.set(0, 1.6, -0.5);
      const targetX = aimRef.current.x * TARGET_RADIUS * 0.8;
      const targetY = 1.6 + aimRef.current.y * TARGET_RADIUS * 0.8;
      let progress = 0;
      const fly = () => {
        progress += 0.04;
        arrow.position.set(
          THREE.MathUtils.lerp(0, targetX, progress),
          THREE.MathUtils.lerp(1.6, targetY, progress),
          THREE.MathUtils.lerp(-0.5, TARGET_Z + 0.1, progress)
        );
        arrow.lookAt(targetX, targetY, TARGET_Z);
        if (progress < 1) requestAnimationFrame(fly);
        else sceneRef.current?.scene.remove(arrow);
      };
      fly();
    }

    socket.emit('archery:shoot', {
      roomId,
      playerId,
      aimNorm: aimRef.current,
      power,
    });

    pullRef.current = 0;
    aimRef.current = { x: 0, y: 0 };
  }, [isMyTurn, roomId, playerId, socket]);

  const currentPlayer = players.find(p => p.id === gameState.players[gameState.currentPlayerIndex]);
  const myTurn = isMyTurn();

  return (
    <div className="relative w-full h-full select-none">
      <canvas
        ref={canvasRef}
        className="w-full h-full"
        style={{ cursor: myTurn ? 'crosshair' : 'default', touchAction: 'none' }}
        onPointerDown={onPointerDown}
        onPointerMove={onPointerMove}
        onPointerUp={onPointerUp}
        onPointerLeave={onPointerUp}
      />

      {/* HUD — scores */}
      <div className="absolute top-4 left-4 right-4 flex justify-between pointer-events-none">
        <div className="bg-black/60 backdrop-blur rounded-xl px-4 py-2 text-sm">
          <div className="text-slate-400 text-xs mb-1">Set {gameState.currentSet}/{ARCHERY_RULES.sets} · Arrow {gameState.arrowsFiredThisSet % ARCHERY_RULES.arrowsPerSet + 1}/{ARCHERY_RULES.arrowsPerSet}</div>
          {players.map(p => (
            <div key={p.id} className={`flex gap-3 ${p.id === playerId ? 'text-green-400' : 'text-white'}`}>
              <span className="font-bold">{p.username}</span>
              <span>{totals[p.id] ?? 0} pts</span>
            </div>
          ))}
        </div>

        {/* Wind indicator */}
        {ARCHERY_RULES.maxWindSpeed > 0 && (
          <div className="bg-black/60 backdrop-blur rounded-xl px-4 py-2 text-xs text-slate-300">
            <div className="text-slate-500 mb-0.5">Wind</div>
            <div>{Math.sqrt(gameState.wind.x ** 2 + gameState.wind.y ** 2).toFixed(1)} m/s</div>
            <div style={{ transform: `rotate(${Math.atan2(gameState.wind.y, gameState.wind.x) * 180 / Math.PI}deg)` }} className="text-lg text-center">→</div>
          </div>
        )}
      </div>

      {/* Turn indicator */}
      <div className="absolute bottom-24 left-1/2 -translate-x-1/2 pointer-events-none">
        {myTurn ? (
          <div className="bg-green-900/80 backdrop-blur border border-green-600 rounded-xl px-5 py-2 text-green-300 text-sm font-bold">
            Your turn — drag left to pull, release to shoot
          </div>
        ) : (
          <div className="bg-black/60 backdrop-blur rounded-xl px-5 py-2 text-slate-400 text-sm">
            {currentPlayer?.username ?? '...'} is shooting…
          </div>
        )}
      </div>

      {/* Last shot result */}
      {lastShot && (
        <div className="absolute bottom-40 left-1/2 -translate-x-1/2 pointer-events-none animate-bounce">
          <div className={`rounded-xl px-4 py-2 text-center font-bold text-lg ${lastShot.shot.miss ? 'bg-red-900/80 text-red-300' : 'bg-yellow-900/80 text-yellow-300'}`}>
            {lastShot.shot.miss ? 'MISS' : `${lastShot.shot.ringLabel} · ${lastShot.shot.points} pts`}
          </div>
        </div>
      )}

      {/* Pull power indicator */}
      {myTurn && (
        <div className="absolute bottom-8 left-1/2 -translate-x-1/2 w-48 pointer-events-none">
          <div className="text-xs text-slate-400 text-center mb-1">Pull power</div>
          <div className="h-2 bg-slate-800 rounded-full overflow-hidden">
            <div className="h-full bg-green-500 transition-none rounded-full" style={{ width: `${pullRef.current * 100}%` }} id="pull-bar" />
          </div>
        </div>
      )}

      {/* Game over overlay */}
      {gameOver && (
        <div className="absolute inset-0 bg-black/75 flex items-center justify-center">
          <div className="bg-slate-900 border border-slate-700 rounded-2xl p-8 text-center max-w-sm w-full mx-4">
            <div className="text-5xl mb-4">🏹</div>
            <h2 className="text-2xl font-bold mb-2">
              {winners.includes(playerId) ? '🏆 You Win!' : 'Game Over'}
            </h2>
            <div className="space-y-1 mb-6">
              {players
                .sort((a, b) => (totals[b.id] ?? 0) - (totals[a.id] ?? 0))
                .map((p, i) => (
                  <div key={p.id} className={`flex justify-between px-3 py-1.5 rounded-lg ${p.id === playerId ? 'bg-green-900/40 text-green-300' : 'text-slate-300'}`}>
                    <span>{i + 1}. {p.username}</span>
                    <span className="font-bold">{totals[p.id] ?? 0} pts</span>
                  </div>
                ))}
            </div>
            <button onClick={() => window.location.href = '/games/archery'}
              className="w-full py-3 bg-green-700 hover:bg-green-600 text-white font-bold rounded-lg transition-colors">
              Play Again
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

'use client';

import { useParams, useSearchParams, useRouter } from 'next/navigation';
import { Suspense, useEffect, useRef, useState } from 'react';
import { io, Socket } from 'socket.io-client';
import dynamic from 'next/dynamic';
import type { ArcheryGameState } from '@/lib/games/archery/ArcheryEngine';

// Load scene client-only (Three.js requires browser)
const ArcheryScene = dynamic(() => import('../ArcheryScene'), { ssr: false });

function ArcheryGame() {
  const { sessionId } = useParams<{ sessionId: string }>();
  const search   = useSearchParams();
  const router   = useRouter();
  const token    = search.get('token');
  const username = search.get('username') || 'Player';
  const mode     = search.get('mode') || 'matchmaking';

  const socketRef = useRef<Socket | null>(null);
  const [status, setStatus]       = useState<'connecting' | 'waiting' | 'playing'>('connecting');
  const [waitInfo, setWaitInfo]   = useState<{ playerCount: number; minPlayers: number; maxPlayers: number } | null>(null);
  const [roomId, setRoomId]       = useState('');
  const [playerId, setPlayerId]   = useState('');
  const [players, setPlayers]     = useState<{ id: string; username: string }[]>([]);
  const [gameState, setGameState] = useState<ArcheryGameState | null>(null);

  useEffect(() => {
    if (!token) return;

    const socket = io('/archery', {
      path: '/api/socket/io',
      transports: ['websocket'],
    });
    socketRef.current = socket;

    const pid = `user_${Date.now()}`;
    setPlayerId(pid);

    socket.on('connect', () => {
      setStatus('connecting');
      if (mode === 'bot') {
        socket.emit('matchmaking:join_bot', { username, playerId: pid, sessionId });
      } else {
        socket.emit('matchmaking:join', { username, playerId: pid, sessionId });
      }
    });

    socket.on('matchmaking:waiting', (data: { playerCount: number; minPlayers: number; maxPlayers: number }) => {
      setStatus('waiting');
      setWaitInfo(data);
    });

    socket.on('game:started', (data: { roomId: string; players: any[]; state: ArcheryGameState }) => {
      setRoomId(data.roomId);
      setPlayers(data.players.map(p => ({ id: p.id, username: p.username })));
      setGameState(data.state);
      setStatus('playing');
    });

    socket.on('error', (err: { message: string }) => {
      console.error('[archery]', err.message);
    });

    return () => { socket.disconnect(); };
  }, [token, mode, username, sessionId]);

  if (!token) return (
    <div className="min-h-screen bg-[#0a0f0a] flex items-center justify-center text-white">
      <p className="text-slate-400">Missing session token.</p>
    </div>
  );

  if (status === 'connecting') return (
    <div className="min-h-screen bg-[#0a0f0a] flex flex-col items-center justify-center text-white gap-4">
      <div className="text-5xl animate-bounce">🏹</div>
      <div className="w-8 h-8 border-2 border-green-500 border-t-transparent rounded-full animate-spin" />
      <p className="text-slate-400 text-sm">Connecting…</p>
    </div>
  );

  if (status === 'waiting') return (
    <div className="min-h-screen bg-[#0a0f0a] flex flex-col items-center justify-center text-white gap-6">
      <div className="text-6xl">🏹</div>
      <div className="text-center">
        <p className="text-xl font-bold mb-1">Waiting for players</p>
        {waitInfo && (
          <p className="text-slate-400 text-sm">
            {waitInfo.playerCount} / {waitInfo.maxPlayers} joined · need at least {waitInfo.minPlayers}
          </p>
        )}
      </div>
      <div className="w-8 h-8 border-2 border-green-500 border-t-transparent rounded-full animate-spin" />
      <button onClick={() => { socketRef.current?.emit('matchmaking:leave', { playerId }); router.push('/games/archery'); }}
        className="text-slate-500 hover:text-slate-300 text-sm transition-colors">
        Cancel
      </button>
    </div>
  );

  if (!gameState || !socketRef.current) return null;

  return (
    <div className="w-screen h-screen bg-black flex flex-col">
      <div className="border-b border-slate-800 px-4 py-2 flex items-center gap-3 bg-black/80 z-10">
        <button onClick={() => router.push('/games/archery')} className="text-slate-400 hover:text-white text-sm">← Leave</button>
        <span className="text-slate-700">|</span>
        <span className="text-lg">🏹</span>
        <span className="text-white font-bold">Archery</span>
        <span className="ml-auto text-xs font-mono text-green-400/50">{sessionId.slice(0, 8)}…</span>
      </div>
      <div className="flex-1 overflow-hidden">
        <ArcheryScene
          socket={socketRef.current}
          roomId={roomId}
          playerId={playerId}
          players={players}
          initialState={gameState}
        />
      </div>
    </div>
  );
}

export default function ArcheryGamePage() {
  return (
    <Suspense fallback={
      <div className="min-h-screen bg-[#0a0f0a] flex items-center justify-center">
        <div className="text-5xl animate-bounce">🏹</div>
      </div>
    }>
      <ArcheryGame />
    </Suspense>
  );
}

