-- =============================================================================
-- Beta Gamer GaaS — Full Schema (single source of truth)
-- Drop everything and recreate clean.
-- Run in Supabase → SQL Editor
-- =============================================================================

-- ─── Drop all tables (reverse dependency order) ───────────────────────────────

drop table if exists bot_training_jobs        cascade;
drop table if exists bot_matchmaking_config   cascade;
drop table if exists game_records             cascade;
drop table if exists tenant_bots              cascade;
drop table if exists tenant_integrity         cascade;
drop table if exists email_verifications      cascade;
drop table if exists tenant_oauth_accounts    cascade;
drop table if exists webhook_deliveries       cascade;
drop table if exists usage_events             cascade;
drop table if exists sessions_chess           cascade;
drop table if exists sessions_checkers        cascade;
drop table if exists sessions_connect4        cascade;
drop table if exists sessions_tictactoe       cascade;
drop table if exists sessions_subway_runner   cascade;
drop table if exists sessions_pool            cascade;
drop table if exists sessions_chkobe          cascade;
drop table if exists tenants                  cascade;

-- ─── Tenants ──────────────────────────────────────────────────────────────────
-- Auth is handled entirely by Supabase Auth (auth.users).
-- tenants.user_id links to the auth user.

create table tenants (
  id              uuid        primary key default gen_random_uuid(),
  user_id         uuid        unique references auth.users(id) on delete cascade,
  name            text        not null,
  email           text        not null unique,
  live_api_key    text        not null unique,  -- bg_live_xxx
  test_api_key    text        not null unique,  -- bg_test_xxx
  webhook_url     text,
  webhook_secret  text        not null,
  allowed_origins text[]      not null default '{}',
  theme           jsonb       not null default '{}',
  plan            text        not null default 'starter'
                              check (plan in ('starter','growth','pro','enterprise')),
  is_active       boolean     not null default true,
  created_at      timestamptz not null default now()
);

create index idx_tenants_live_key on tenants(live_api_key);
create index idx_tenants_test_key on tenants(test_api_key);

-- ─── Game sessions ────────────────────────────────────────────────────────────
-- One table per game. All share the same base columns.
-- game-specific extras noted inline.

-- Reusable game list for constraints
-- chess | checkers | connect4 | tictactoe | subway-runner | pool | chkobe

-- CHESS
create table sessions_chess (
  id           uuid        primary key default gen_random_uuid(),
  tenant_id    uuid        not null references tenants(id) on delete cascade,
  mode         text        not null default 'live'         check (mode       in ('live','test','training')),
  match_type   text        not null default 'matchmaking'  check (match_type in ('matchmaking','private','bot')),
  room_code    text        unique,
  players      jsonb       not null,
  status       text        not null default 'pending'      check (status     in ('pending','active','ended')),
  result       jsonb,
  pgn          text,
  time_control int,
  created_at   timestamptz not null default now(),
  ended_at     timestamptz
);

-- CHECKERS
create table sessions_checkers (
  id           uuid        primary key default gen_random_uuid(),
  tenant_id    uuid        not null references tenants(id) on delete cascade,
  mode         text        not null default 'live'         check (mode       in ('live','test','training')),
  match_type   text        not null default 'matchmaking'  check (match_type in ('matchmaking','private','bot')),
  room_code    text        unique,
  players      jsonb       not null,
  status       text        not null default 'pending'      check (status     in ('pending','active','ended')),
  result       jsonb,
  created_at   timestamptz not null default now(),
  ended_at     timestamptz
);

-- CONNECT4
create table sessions_connect4 (
  id           uuid        primary key default gen_random_uuid(),
  tenant_id    uuid        not null references tenants(id) on delete cascade,
  mode         text        not null default 'live'         check (mode       in ('live','test','training')),
  match_type   text        not null default 'matchmaking'  check (match_type in ('matchmaking','private','bot')),
  room_code    text        unique,
  players      jsonb       not null,
  status       text        not null default 'pending'      check (status     in ('pending','active','ended')),
  result       jsonb,
  created_at   timestamptz not null default now(),
  ended_at     timestamptz
);

-- TICTACTOE
create table sessions_tictactoe (
  id           uuid        primary key default gen_random_uuid(),
  tenant_id    uuid        not null references tenants(id) on delete cascade,
  mode         text        not null default 'live'         check (mode       in ('live','test','training')),
  match_type   text        not null default 'matchmaking'  check (match_type in ('matchmaking','private','bot')),
  room_code    text        unique,
  players      jsonb       not null,
  status       text        not null default 'pending'      check (status     in ('pending','active','ended')),
  result       jsonb,
  created_at   timestamptz not null default now(),
  ended_at     timestamptz
);

-- SUBWAY RUNNER (single-player only)
create table sessions_subway_runner (
  id           uuid        primary key default gen_random_uuid(),
  tenant_id    uuid        not null references tenants(id) on delete cascade,
  mode         text        not null default 'live'         check (mode       in ('live','test','training')),
  match_type   text        not null default 'bot'          check (match_type in ('bot')),
  players      jsonb       not null,
  status       text        not null default 'pending'      check (status     in ('pending','active','ended')),
  result       jsonb,
  created_at   timestamptz not null default now(),
  ended_at     timestamptz
);

-- POOL
create table sessions_pool (
  id           uuid        primary key default gen_random_uuid(),
  tenant_id    uuid        not null references tenants(id) on delete cascade,
  mode         text        not null default 'live'         check (mode       in ('live','test','training')),
  match_type   text        not null default 'matchmaking'  check (match_type in ('matchmaking','private','bot')),
  room_code    text        unique,
  players      jsonb       not null,
  status       text        not null default 'pending'      check (status     in ('pending','active','ended')),
  result       jsonb,
  created_at   timestamptz not null default now(),
  ended_at     timestamptz
);

-- CHKOBÉ (2–8 players, turn-based card game)
-- winners is an ordered array of player ids (position 0 = 1st place)
create table sessions_chkobe (
  id           uuid        primary key default gen_random_uuid(),
  tenant_id    uuid        not null references tenants(id) on delete cascade,
  mode         text        not null default 'live'         check (mode       in ('live','test','training')),
  match_type   text        not null default 'matchmaking'  check (match_type in ('matchmaking','private','bot')),
  room_code    text        unique,
  players      jsonb       not null,
  status       text        not null default 'pending'      check (status     in ('pending','active','ended')),
  result       jsonb,      -- { winner, winners[], reason, winCondition }
  win_condition text       check (win_condition in ('first_empty','last_standing','weighted_score')),
  created_at   timestamptz not null default now(),
  ended_at     timestamptz
);

-- ─── Session indexes ──────────────────────────────────────────────────────────

create index idx_chess_tenant        on sessions_chess(tenant_id, mode);
create index idx_checkers_tenant     on sessions_checkers(tenant_id, mode);
create index idx_connect4_tenant     on sessions_connect4(tenant_id, mode);
create index idx_tictactoe_tenant    on sessions_tictactoe(tenant_id, mode);
create index idx_runner_tenant       on sessions_subway_runner(tenant_id, mode);
create index idx_pool_tenant         on sessions_pool(tenant_id, mode);
create index idx_chkobe_tenant       on sessions_chkobe(tenant_id, mode);

-- Training pool indexes (cross-tenant matchmaking)
create index idx_chess_training      on sessions_chess(mode, status)          where mode = 'training';
create index idx_checkers_training   on sessions_checkers(mode, status)       where mode = 'training';
create index idx_connect4_training   on sessions_connect4(mode, status)       where mode = 'training';
create index idx_tictactoe_training  on sessions_tictactoe(mode, status)      where mode = 'training';
create index idx_pool_training       on sessions_pool(mode, status)           where mode = 'training';
create index idx_chkobe_training     on sessions_chkobe(mode, status)         where mode = 'training';

-- ─── Webhook deliveries ───────────────────────────────────────────────────────

create table webhook_deliveries (
  id           uuid        primary key default gen_random_uuid(),
  tenant_id    uuid        not null references tenants(id) on delete cascade,
  session_id   uuid        not null,
  game         text        not null,
  event        text        not null,
  payload      text        not null,
  status       text        not null default 'pending' check (status in ('pending','delivered','failed')),
  attempts     int         not null default 0,
  last_attempt timestamptz,
  created_at   timestamptz not null default now()
);

create index idx_webhooks_tenant on webhook_deliveries(tenant_id, created_at);

-- ─── Usage events ─────────────────────────────────────────────────────────────

create table usage_events (
  id          bigserial   primary key,
  tenant_id   uuid        not null references tenants(id) on delete cascade,
  session_id  uuid        not null,
  game        text        not null,
  mode        text        not null,
  created_at  timestamptz not null default now()
);

create index idx_usage_tenant on usage_events(tenant_id, created_at);

-- ─── Tenant bots ──────────────────────────────────────────────────────────────

create table tenant_bots (
  id                  uuid        primary key default gen_random_uuid(),
  tenant_id           uuid        not null references tenants(id) on delete cascade,
  game                text        not null
                                  check (game in ('chess','checkers','connect4','tictactoe','pool')),
  name                text        not null,
  player_id           text        not null,
  display_name        text        not null,
  bot_type            text        not null check (bot_type in ('algorithmic','learned')),
  matchmaking_weight  int         not null default 100 check (matchmaking_weight >= 0),
  -- algorithmic only
  difficulty          text        check (difficulty in ('easy','medium','hard')),
  -- learned only
  target_rating       int         check (target_rating  in (3,4,5)),
  current_rating      int         check (current_rating between 1 and 5),
  display_rating      int         check (display_rating between 1 and 5),
  model_data          jsonb,
  retrain_threshold   int         not null default 50,
  games_since_retrain int         not null default 0,
  last_trained_at     timestamptz,
  is_active           boolean     not null default true,
  created_at          timestamptz not null default now(),
  unique (tenant_id, game, name),
  constraint chk_bot_algorithmic check (bot_type <> 'algorithmic' or difficulty    is not null),
  constraint chk_bot_learned     check (bot_type <> 'learned'     or target_rating is not null)
);

create index idx_bots_tenant_game on tenant_bots(tenant_id, game);

-- ─── Game records ─────────────────────────────────────────────────────────────

create table game_records (
  id                  uuid        primary key default gen_random_uuid(),
  tenant_id           uuid        not null references tenants(id) on delete cascade,
  game                text        not null
                                  check (game in ('chess','checkers','connect4','tictactoe','pool','chkobe')),
  session_id          uuid        not null,
  players             jsonb       not null,  -- [{ id, displayName, grade }]
  moves               jsonb       not null,  -- full move list
  result              jsonb       not null,  -- { winner, reason, duration, moveCount }
  player_grades       jsonb,                 -- { "<playerId>": 1–5 }
  used_for_training   boolean     not null default false,
  created_at          timestamptz not null default now()
);

create index idx_records_tenant_game         on game_records(tenant_id, game);
create index idx_records_tenant_game_trained on game_records(tenant_id, game, used_for_training);

-- ─── Bot training jobs ────────────────────────────────────────────────────────

create table bot_training_jobs (
  id           uuid        primary key default gen_random_uuid(),
  tenant_id    uuid        not null references tenants(id) on delete cascade,
  bot_id       uuid        not null references tenant_bots(id) on delete cascade,
  game         text        not null,
  trigger      text        not null check (trigger in ('manual','auto','pgn_import','challenge')),
  records_used int,
  status       text        not null default 'pending' check (status in ('pending','running','done','failed')),
  error        text,
  started_at   timestamptz,
  finished_at  timestamptz,
  created_at   timestamptz not null default now()
);

create index idx_training_jobs_bot on bot_training_jobs(bot_id, created_at);

-- ─── Bot matchmaking fallback config ──────────────────────────────────────────

create table bot_matchmaking_config (
  tenant_id          uuid    not null references tenants(id) on delete cascade,
  game               text    not null
                             check (game in ('chess','checkers','connect4','tictactoe','pool')),
  fallback_delay_sec int     not null default 15,
  enabled            boolean not null default true,
  primary key (tenant_id, game)
);

-- ─── App integrity credentials ────────────────────────────────────────────────

create table tenant_integrity (
  tenant_id  uuid        not null references tenants(id) on delete cascade,
  platform   text        not null check (platform in ('android','ios')),
  credential jsonb       not null,
  created_at timestamptz not null default now(),
  primary key (tenant_id, platform)
);

-- ─── Row Level Security ───────────────────────────────────────────────────────
-- Service role bypasses RLS. Anon/authenticated keys see nothing by default.

alter table tenants                enable row level security;
alter table sessions_chess         enable row level security;
alter table sessions_checkers      enable row level security;
alter table sessions_connect4      enable row level security;
alter table sessions_tictactoe     enable row level security;
alter table sessions_subway_runner enable row level security;
alter table sessions_pool          enable row level security;
alter table sessions_chkobe        enable row level security;
alter table webhook_deliveries     enable row level security;
alter table usage_events           enable row level security;
alter table tenant_bots            enable row level security;
alter table game_records           enable row level security;
alter table bot_training_jobs      enable row level security;
alter table bot_matchmaking_config enable row level security;
alter table tenant_integrity       enable row level security;

