=== Operation 1 Result (Text) ===
/**
 * PoolEventBus — decouples input controllers from game logic.
 * Controllers fire events; the game listens and reacts.
 */

export interface PoolControlEvents {
  'pool:aim':       { rotation: number };           // cue angle in radians
  'pool:power':     { power: number };              // 0–75
  'pool:shoot':     {};                             // fire the shot
  'pool:placeBall': { x: number; y: number };       // ball-in-hand placement
}

type Listener<T> = (data: T) => void;

export class PoolEventBus {
  private listeners: { [K in keyof PoolControlEvents]?: Listener<PoolControlEvents[K]>[] } = {};

  on<K extends keyof PoolControlEvents>(event: K, cb: Listener<PoolControlEvents[K]>) {
    (this.listeners[event] ??= [] as any).push(cb);
  }

  off<K extends keyof PoolControlEvents>(event: K, cb: Listener<PoolControlEvents[K]>) {
    this.listeners[event] = (this.listeners[event] ?? []).filter(l => l !== cb) as any;
  }

  emit<K extends keyof PoolControlEvents>(event: K, data: PoolControlEvents[K]) {
    (this.listeners[event] ?? []).forEach(cb => (cb as Listener<PoolControlEvents[K]>)(data));
  }
}

=== Operation 2 Result (Text) ===
/**
 * PoolControllerContext — provides the PoolEventBus and game state accessor to any controller component.
 * Controllers call useBus() to get the bus and fire events onto it.
 * Controllers call usePoolState() to read current game state.
 */
import { createContext, useContext } from 'react';
import { PoolEventBus } from './PoolEventBus';

export interface PoolGameState {
  ballInHand: boolean;
  myTurn:     boolean;
}

interface PoolControllerCtx {
  bus:      PoolEventBus;
  getState: () => PoolGameState;
}

export const PoolControllerContext = createContext<PoolControllerCtx | null>(null);

export function useBus(): PoolEventBus {
  const ctx = useContext(PoolControllerContext);
  if (!ctx) throw new Error('useBus must be used inside PoolSDKRoom');
  return ctx.bus;
}

export function usePoolState(): () => PoolGameState {
  const ctx = useContext(PoolControllerContext);
  if (!ctx) throw new Error('usePoolState must be used inside PoolSDKRoom');
  return ctx.getState;
}

