/**
 * TwoZoneController — touch controller splitting screen into two zones.
 * aimSide:   which side controls aim (drag to rotate cue)
 * powerSide: which side controls power (drag up = more power, tap = shoot)
 *
 * Fires pool:aim, pool:power, pool:shoot, pool:placeBall onto the bus.
 */
'use client';
import { useEffect, useRef } from 'react';
import { useBus, usePoolState } from '../PoolControllerContext';

const MAX_POWER = 75;

interface Props {
  canvas:     HTMLCanvasElement | null;
  aimSide?:   'left' | 'right'; // default: left
  powerSide?: 'left' | 'right'; // default: right
}

export function TwoZoneController({ canvas, aimSide = 'left', powerSide = 'right' }: Props) {
  const bus        = useBus();
  const getState   = usePoolState();
  const power      = useRef(0);
  const aimStart   = useRef<{ x: number; y: number } | null>(null);
  const powerStart = useRef<number | null>(null);
  const ballPos    = useRef<{ x: number; y: number } | null>(null); // tracks ball position during ball-in-hand

  useEffect(() => {
    if (!canvas) return;

    const midX = () => window.innerWidth / 2;

    const isAimSide   = (x: number) => aimSide   === 'left' ? x < midX() : x >= midX();
    const isPowerSide = (x: number) => powerSide  === 'left' ? x < midX() : x >= midX();

    const toGame = (ex: number, ey: number) => {
      const r = canvas.getBoundingClientRect();
      return { x: (ex - r.left) / r.width * canvas.width, y: (ey - r.top) / r.height * canvas.height };
    };

    const onTouchStart = (e: TouchEvent) => {
      for (const t of Array.from(e.changedTouches)) {
        if (isAimSide(t.clientX))   aimStart.current   = { x: t.clientX, y: t.clientY };
        if (isPowerSide(t.clientX)) { powerStart.current = t.clientY; power.current = 0; }
      }
    };

    const onTouchMove = (e: TouchEvent) => {
      const { ballInHand, myTurn } = getState();
      if (ballInHand && myTurn) { e.preventDefault(); return; } // ignore move during ball-in-hand
      for (const t of Array.from(e.changedTouches)) {
        if (isAimSide(t.clientX) && aimStart.current) {
          const dx = t.clientX - aimStart.current.x;
          const dy = t.clientY - aimStart.current.y;
          if (Math.abs(dx) > 2 || Math.abs(dy) > 2) {
            bus.emit('pool:aim', { rotation: Math.atan2(dy, dx) });
          }
        }
        if (isPowerSide(t.clientX) && powerStart.current !== null) {
          const dragUp = Math.max(0, powerStart.current - t.clientY);
          power.current = Math.min(MAX_POWER, (dragUp / 150) * MAX_POWER);
          bus.emit('pool:power', { power: power.current });
        }
      }
      e.preventDefault();
    };

    const onTouchEnd = (e: TouchEvent) => {
      const { ballInHand, myTurn } = getState();
      for (const t of Array.from(e.changedTouches)) {
        if (ballInHand && myTurn) {
          // Tap anywhere to place ball at that position
          bus.emit('pool:placeBall', toGame(t.clientX, t.clientY));
          ballPos.current = null;
          return;
        }
        if (isPowerSide(t.clientX)) {
          if (power.current > 0) bus.emit('pool:shoot', {});
          power.current      = 0;
          powerStart.current = null;
        }
        if (isAimSide(t.clientX)) aimStart.current = null;
      }
    };

    canvas.addEventListener('touchstart', onTouchStart, { passive: false });
    canvas.addEventListener('touchmove',  onTouchMove,  { passive: false });
    canvas.addEventListener('touchend',   onTouchEnd);
    return () => {
      canvas.removeEventListener('touchstart', onTouchStart);
      canvas.removeEventListener('touchmove',  onTouchMove);
      canvas.removeEventListener('touchend',   onTouchEnd);
    };
  }, [canvas, bus, aimSide, powerSide]);

  return null;
}

=== Operation 2 Result (Text) ===
/**
 * MouseController — default desktop controller.
 * Mouse move = aim, W/S keys = power, left click = shoot.
 * Fires pool:aim, pool:power, pool:shoot, pool:placeBall onto the bus.
 */
'use client';
import { useEffect, useRef } from 'react';
import { useBus } from '../PoolControllerContext';

const MAX_POWER = 75;

export function MouseController({ canvas }: { canvas: HTMLCanvasElement | null }) {
  const bus   = useBus();
  const power = useRef(0);

  useEffect(() => {
    if (!canvas) return;

    const toGame = (ex: number, ey: number) => {
      const r = canvas.getBoundingClientRect();
      return { x: (ex - r.left) / r.width * canvas.width, y: (ey - r.top) / r.height * canvas.height };
    };

    const onMove  = (e: MouseEvent) => {
      const p = toGame(e.clientX, e.clientY);
      bus.emit('pool:aim', { rotation: Math.atan2(p.y - canvas.height / 2, p.x - canvas.width / 2) });
    };
    const onClick = (e: MouseEvent) => {
      if (e.button !== 0) return;
      if (power.current > 0) {
        bus.emit('pool:shoot', {});
        power.current = 0;
      } else {
        // ball-in-hand placement
        const p = toGame(e.clientX, e.clientY);
        bus.emit('pool:placeBall', p);
      }
    };
    const onKeyDown = (e: KeyboardEvent) => {
      if (e.code === 'KeyW' && power.current < MAX_POWER) {
        power.current = Math.min(MAX_POWER, power.current + 1.2);
        bus.emit('pool:power', { power: power.current });
      } else if (e.code === 'KeyS' && power.current > 0) {
        power.current = Math.max(0, power.current - 1.2);
        bus.emit('pool:power', { power: power.current });
      }
    };

    document.addEventListener('mousemove', onMove);
    document.addEventListener('click',     onClick);
    document.addEventListener('keydown',   onKeyDown);
    return () => {
      document.removeEventListener('mousemove', onMove);
      document.removeEventListener('click',     onClick);
      document.removeEventListener('keydown',   onKeyDown);
    };
  }, [canvas, bus]);

  return null; // no UI
}

