/**
 * ArcheryEventBus — decouples input controllers from game logic.
 * Controllers fire events; the scene listens and reacts.
 * Developers can build custom controllers by emitting these events.
 */

export interface ArcheryControlEvents {
  /** Fired continuously while aiming — normalised offset from center (-1..1 each axis) */
  'archery:aim':   { aimNorm: { x: number; y: number } };
  /** Fired while pulling — 0 (no pull) to 1 (full draw) */
  'archery:pull':  { power: number };
  /** Fired on release — triggers the shot */
  'archery:shoot': { aimNorm: { x: number; y: number }; power: number };
}

type Listener<T> = (data: T) => void;

export class ArcheryEventBus {
  private listeners: { [K in keyof ArcheryControlEvents]?: Listener<ArcheryControlEvents[K]>[] } = {};

  on<K extends keyof ArcheryControlEvents>(event: K, cb: Listener<ArcheryControlEvents[K]>) {
    (this.listeners[event] ??= [] as any).push(cb);
  }

  off<K extends keyof ArcheryControlEvents>(event: K, cb: Listener<ArcheryControlEvents[K]>) {
    this.listeners[event] = (this.listeners[event] ?? []).filter(l => l !== cb) as any;
  }

  emit<K extends keyof ArcheryControlEvents>(event: K, data: ArcheryControlEvents[K]) {
    (this.listeners[event] ?? []).forEach(cb => (cb as Listener<ArcheryControlEvents[K]>)(data));
  }
}

/**
 * ArcheryControllerContext — provides the ArcheryEventBus and game state
 * accessor to any controller component.
 */
import { createContext, useContext } from 'react';
import { ArcheryEventBus } from './ArcheryEventBus';

export interface ArcheryGameState {
  myTurn: boolean;
}

interface ArcheryControllerCtx {
  bus:      ArcheryEventBus;
  getState: () => ArcheryGameState;
}

export const ArcheryControllerContext = createContext<ArcheryControllerCtx | null>(null);

export function useBus(): ArcheryEventBus {
  const ctx = useContext(ArcheryControllerContext);
  if (!ctx) throw new Error('useBus must be used inside ArcheryScene');
  return ctx.bus;
}

export function useArcheryState(): () => ArcheryGameState {
  const ctx = useContext(ArcheryControllerContext);
  if (!ctx) throw new Error('useArcheryState must be used inside ArcheryScene');
  return ctx.getState;
}

/**
 * MouseController (desktop) — default archery controller.
 * - Mouse move = aim (moves crosshair on target)
 * - Hold left mouse button + drag left = pull power
 * - Release = shoot
 */
'use client';
import { useEffect, useRef } from 'react';
import { useBus, useArcheryState } from '../../lib/games/archery/ArcheryControllerContext';

export function ArcheryMouseController({ canvas }: { canvas: HTMLCanvasElement | null }) {
  const bus      = useBus();
  const getState = useArcheryState();
  const pulling  = useRef(false);
  const pullOriginX = useRef(0);
  const aimNorm  = useRef({ x: 0, y: 0 });
  const power    = useRef(0);

  useEffect(() => {
    if (!canvas) return;

    const toNorm = (ex: number, ey: number) => ({
      x:  ((ex - window.innerWidth  / 2) / (window.innerWidth  / 2)),
      y: -((ey - window.innerHeight / 2) / (window.innerHeight / 2)),
    });

    const onMove = (e: MouseEvent) => {
      if (!getState().myTurn) return;
      aimNorm.current = toNorm(e.clientX, e.clientY);
      bus.emit('archery:aim', { aimNorm: aimNorm.current });

      if (pulling.current) {
        const dragLeft = Math.max(0, pullOriginX.current - e.clientX);
        power.current  = Math.min(1, dragLeft / (window.innerWidth * 0.25));
        bus.emit('archery:pull', { power: power.current });
      }
    };

    const onDown = (e: MouseEvent) => {
      if (e.button !== 0 || !getState().myTurn) return;
      pulling.current   = true;
      pullOriginX.current = e.clientX;
      power.current     = 0;
    };

    const onUp = (e: MouseEvent) => {
      if (e.button !== 0 || !pulling.current) return;
      pulling.current = false;
      if (power.current > 0.05) {
        bus.emit('archery:shoot', { aimNorm: aimNorm.current, power: power.current });
      }
      power.current = 0;
      bus.emit('archery:pull', { power: 0 });
    };

    canvas.addEventListener('mousemove', onMove);
    canvas.addEventListener('mousedown', onDown);
    window.addEventListener('mouseup',   onUp);
    return () => {
      canvas.removeEventListener('mousemove', onMove);
      canvas.removeEventListener('mousedown', onDown);
      window.removeEventListener('mouseup',   onUp);
    };
  }, [canvas, bus, getState]);

  return null;
}

/**
 * TouchController (mobile) — two-zone archery controller.
 * Left zone:  drag to aim
 * Right zone: drag left to pull, release to shoot
 */
'use client';
import { useEffect, useRef } from 'react';
import { useBus, useArcheryState } from '../../lib/games/archery/ArcheryControllerContext';

export function ArcheryTouchController({ canvas }: { canvas: HTMLCanvasElement | null }) {
  const bus      = useBus();
  const getState = useArcheryState();
  const aimNorm  = useRef({ x: 0, y: 0 });
  const pullOriginX = useRef<number | null>(null);
  const power    = useRef(0);

  useEffect(() => {
    if (!canvas) return;

    const midX = () => window.innerWidth / 2;

    const toNorm = (ex: number, ey: number) => ({
      x:  ((ex - window.innerWidth  / 2) / (window.innerWidth  / 2)),
      y: -((ey - window.innerHeight / 2) / (window.innerHeight / 2)),
    });

    const onTouchStart = (e: TouchEvent) => {
      if (!getState().myTurn) return;
      for (const t of Array.from(e.changedTouches)) {
        if (t.clientX < midX()) {
          // aim zone — record start for delta aim
        } else {
          pullOriginX.current = t.clientX;
          power.current = 0;
        }
      }
      e.preventDefault();
    };

    const onTouchMove = (e: TouchEvent) => {
      if (!getState().myTurn) return;
      for (const t of Array.from(e.changedTouches)) {
        if (t.clientX < midX()) {
          aimNorm.current = toNorm(t.clientX * 2, t.clientY); // scale left half to full range
          bus.emit('archery:aim', { aimNorm: aimNorm.current });
        } else if (pullOriginX.current !== null) {
          const dragLeft = Math.max(0, pullOriginX.current - t.clientX);
          power.current  = Math.min(1, dragLeft / (window.innerWidth * 0.2));
          bus.emit('archery:pull', { power: power.current });
        }
      }
      e.preventDefault();
    };

    const onTouchEnd = (e: TouchEvent) => {
      if (!getState().myTurn) return;
      for (const t of Array.from(e.changedTouches)) {
        if (t.clientX >= midX() && pullOriginX.current !== null) {
          if (power.current > 0.05) {
            bus.emit('archery:shoot', { aimNorm: aimNorm.current, power: power.current });
          }
          pullOriginX.current = null;
          power.current = 0;
          bus.emit('archery:pull', { power: 0 });
        }
      }
    };

    canvas.addEventListener('touchstart', onTouchStart, { passive: false });
    canvas.addEventListener('touchmove',  onTouchMove,  { passive: false });
    canvas.addEventListener('touchend',   onTouchEnd);
    return () => {
      canvas.removeEventListener('touchstart', onTouchStart);
      canvas.removeEventListener('touchmove',  onTouchMove);
      canvas.removeEventListener('touchend',   onTouchEnd);
    };
  }, [canvas, bus, getState]);

  return null;
}

'use client';

import { useEffect, useRef, useState, useCallback, useMemo } from 'react';
import * as THREE from 'three';
import { ARCHERY_RULES } from '@/lib/games/archery/rules';
import type { ArcheryGameState, ArrowShot, Vec2 } from '@/lib/games/archery/ArcheryEngine';
import { ArcheryEventBus } from '@/lib/games/archery/ArcheryEventBus';
import { ArcheryControllerContext } from '@/lib/games/archery/ArcheryControllerContext';
import { ArcheryMouseController } from './controllers/MouseController';
import { ArcheryTouchController } from './controllers/TouchController';

// ─── Types ────────────────────────────────────────────────────────────────────

interface ShotResult {
  playerId: string;
  shot: ArrowShot;
  state: ArcheryGameState;
  totals: Record<string, number>;
}

interface PlayerInfo { id: string; username: string; }

interface Props {
  socket: any;
  roomId: string;
  playerId: string;
  players: PlayerInfo[];
  initialState: ArcheryGameState;
  /** Optional custom controller — if omitted, default mouse+touch controllers are used */
  controller?: React.ReactNode;
}

// ─── Constants ────────────────────────────────────────────────────────────────

const TARGET_Z      = -40;
const TARGET_RADIUS = 3.5;
const PARTICLE_COUNT = 120;

// ─── Scene builder ────────────────────────────────────────────────────────────

function buildScene(canvas: HTMLCanvasElement) {
  const renderer = new THREE.WebGLRenderer({ canvas, antialias: true });
  renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
  renderer.shadowMap.enabled = true;
  renderer.shadowMap.type = THREE.PCFSoftShadowMap;
  renderer.toneMapping = THREE.ACESFilmicToneMapping;
  renderer.toneMappingExposure = 1.1;

  const scene = new THREE.Scene();
  scene.background = new THREE.Color(0x87ceeb);
  scene.fog = new THREE.FogExp2(0x87ceeb, 0.008);

  const camera = new THREE.PerspectiveCamera(65, canvas.clientWidth / canvas.clientHeight, 0.1, 300);
  camera.position.set(0, 1.6, 0);
  camera.lookAt(0, 1.6, TARGET_Z);

  // Lighting
  scene.add(new THREE.AmbientLight(0xffffff, 1.2));
  const sun = new THREE.DirectionalLight(0xfff5cc, 2.5);
  sun.position.set(10, 20, -10);
  sun.castShadow = true;
  sun.shadow.mapSize.set(2048, 2048);
  Object.assign(sun.shadow.camera, { far: 120, left: -30, right: 30, top: 20, bottom: -5 });
  scene.add(sun);
  scene.add(new THREE.HemisphereLight(0xadd8ff, 0x44aa44, 0.8));

  // Ground
  const ground = new THREE.Mesh(
    new THREE.PlaneGeometry(80, 120),
    new THREE.MeshLambertMaterial({ color: 0x3a7a3a })
  );
  ground.rotation.x = -Math.PI / 2;
  ground.receiveShadow = true;
  scene.add(ground);

  // Grass tufts
  const tuftMesh = new THREE.InstancedMesh(
    new THREE.ConeGeometry(0.04, 0.25, 4),
    new THREE.MeshLambertMaterial({ color: 0x4a8a4a }),
    600
  );
  const dummy = new THREE.Object3D();
  for (let i = 0; i < 600; i++) {
    dummy.position.set((Math.random() - 0.5) * 70, 0.12, (Math.random() - 0.5) * 110 - 5);
    dummy.rotation.y = Math.random() * Math.PI;
    dummy.scale.setScalar(0.8 + Math.random() * 0.6);
    dummy.updateMatrix();
    tuftMesh.setMatrixAt(i, dummy.matrix);
  }
  scene.add(tuftMesh);

  // Trees
  const trunkMat = new THREE.MeshLambertMaterial({ color: 0x4a3020 });
  const leafMat  = new THREE.MeshLambertMaterial({ color: 0x2e7d2e });
  [[-8,-15],[8,-12],[-10,-25],[9,-28],[-7,-38],[10,-42],[-12,-5],[11,-8],[-9,-50],[8,-55]].forEach(([x,z]) => {
    const trunk = new THREE.Mesh(new THREE.CylinderGeometry(0.12, 0.18, 2.5, 6), trunkMat);
    trunk.position.set(x, 1.25, z); trunk.castShadow = true; scene.add(trunk);
    const leaves = new THREE.Mesh(new THREE.SphereGeometry(1.1, 6, 5), leafMat);
    leaves.position.set(x, 3.2, z); leaves.castShadow = true; scene.add(leaves);
  });

  // Target board
  const targetGroup = new THREE.Group();
  targetGroup.position.set(0, 1.6, TARGET_Z);
  const board = new THREE.Mesh(
    new THREE.BoxGeometry(TARGET_RADIUS * 2.4, TARGET_RADIUS * 2.4, 0.15),
    new THREE.MeshLambertMaterial({ color: 0x8b6914 })
  );
  board.receiveShadow = true;
  targetGroup.add(board);
  [...ARCHERY_RULES.rings].reverse().forEach((ring, i) => {
    const mesh = new THREE.Mesh(
      new THREE.CircleGeometry(ring.radiusNorm * TARGET_RADIUS, 64),
      new THREE.MeshLambertMaterial({ color: new THREE.Color(ring.color) })
    );
    mesh.position.z = 0.08 + i * 0.001;
    targetGroup.add(mesh);
  });
  const post = new THREE.Mesh(
    new THREE.CylinderGeometry(0.06, 0.08, 1.6, 8),
    new THREE.MeshLambertMaterial({ color: 0x5a4010 })
  );
  post.position.set(0, -TARGET_RADIUS * 1.2 - 0.8, 0);
  post.castShadow = true;
  targetGroup.add(post);
  scene.add(targetGroup);

  // Aim dot
  const aimDot = new THREE.Mesh(
    new THREE.RingGeometry(0.07, 0.12, 24),
    new THREE.MeshBasicMaterial({ color: 0xffffff, transparent: true, opacity: 0.85 })
  );
  aimDot.position.set(0, 0, TARGET_Z + 0.15);
  aimDot.visible = false;
  scene.add(aimDot);

  // Bow (camera-space)
  const bowGroup = new THREE.Group();
  const limbMat = new THREE.MeshLambertMaterial({ color: 0x6b3a1f });
  const limbGeo = new THREE.CylinderGeometry(0.018, 0.012, 0.9, 6);
  const topLimb = new THREE.Mesh(limbGeo, limbMat); topLimb.position.set(0, 0.45, 0); topLimb.rotation.z = 0.12; bowGroup.add(topLimb);
  const botLimb = new THREE.Mesh(limbGeo, limbMat); botLimb.position.set(0, -0.45, 0); botLimb.rotation.z = -0.12; bowGroup.add(botLimb);
  const stringPts = [new THREE.Vector3(0.06, 0.82, 0), new THREE.Vector3(0, 0, 0), new THREE.Vector3(0.06, -0.82, 0)];
  const bowString = new THREE.Line(
    new THREE.BufferGeometry().setFromPoints(stringPts),
    new THREE.LineBasicMaterial({ color: 0xddddcc })
  );
  bowGroup.add(bowString);
  const arrowOnBow = new THREE.Mesh(
    new THREE.CylinderGeometry(0.008, 0.008, 0.7, 6),
    new THREE.MeshLambertMaterial({ color: 0xc8a060 })
  );
  arrowOnBow.rotation.x = Math.PI / 2;
  arrowOnBow.position.set(0, 0, -0.35);
  bowGroup.add(arrowOnBow);
  bowGroup.position.set(0.28, -0.22, -0.55);
  camera.add(bowGroup);
  scene.add(camera);

  // Wind particles
  const pPositions = new Float32Array(PARTICLE_COUNT * 3);
  for (let i = 0; i < PARTICLE_COUNT; i++) {
    pPositions[i*3]   = (Math.random()-0.5)*20;
    pPositions[i*3+1] = Math.random()*4;
    pPositions[i*3+2] = (Math.random()-0.5)*60-10;
  }
  const particleGeo = new THREE.BufferGeometry();
  particleGeo.setAttribute('position', new THREE.BufferAttribute(pPositions, 3));
  const particles = new THREE.Points(particleGeo, new THREE.PointsMaterial({ color: 0xaaffaa, size: 0.04, transparent: true, opacity: 0.35 }));
  scene.add(particles);

  return { renderer, scene, camera, bowGroup, bowString, arrowOnBow, particles, aimDot };
}

// ─── Arrow flight animation ───────────────────────────────────────────────────

function animateArrow(scene: THREE.Scene, hitNorm: Vec2, onDone?: () => void) {
  const g = new THREE.Group();
  const shaft = new THREE.Mesh(new THREE.CylinderGeometry(0.008,0.008,0.7,6), new THREE.MeshLambertMaterial({ color: 0xc8a060 }));
  shaft.rotation.x = Math.PI/2; g.add(shaft);
  const tip = new THREE.Mesh(new THREE.ConeGeometry(0.015,0.06,6), new THREE.MeshLambertMaterial({ color: 0x888888 }));
  tip.rotation.x = Math.PI/2; tip.position.z = -0.38; g.add(tip);
  scene.add(g);

  const tx = hitNorm.x * TARGET_RADIUS;
  const ty = 1.6 + hitNorm.y * TARGET_RADIUS;
  let p = 0;
  const fly = () => {
    p += 0.04;
    g.position.set(THREE.MathUtils.lerp(0, tx, p), THREE.MathUtils.lerp(1.6, ty, p), THREE.MathUtils.lerp(-0.5, TARGET_Z+0.1, p));
    g.lookAt(tx, ty, TARGET_Z);
    if (p < 1) requestAnimationFrame(fly);
    else { scene.remove(g); onDone?.(); }
  };
  fly();
}

// ─── Hit marker ───────────────────────────────────────────────────────────────

function placeHitMarker(scene: THREE.Scene, hitNorm: Vec2) {
  const mesh = new THREE.Mesh(
    new THREE.CircleGeometry(0.06, 12),
    new THREE.MeshBasicMaterial({ color: 0xffffff, transparent: true, opacity: 0.9 })
  );
  mesh.position.set(hitNorm.x * TARGET_RADIUS, 1.6 + hitNorm.y * TARGET_RADIUS, TARGET_Z + 0.12);
  scene.add(mesh);
}

// ─── Main component ───────────────────────────────────────────────────────────

export default function ArcheryScene({ socket, roomId, playerId, players, initialState, controller }: Props) {
  const canvasRef    = useRef<HTMLCanvasElement>(null);
  const sceneRef     = useRef<ReturnType<typeof buildScene> | null>(null);
  const stateRef     = useRef<ArcheryGameState>(initialState);
  const aimRef       = useRef<Vec2>({ x: 0, y: 0 });
  const pullRef      = useRef(0);
  const animFrameRef = useRef(0);

  const [gameState, setGameState] = useState<ArcheryGameState>(initialState);
  const [lastShot, setLastShot]   = useState<{ ringLabel: string; points: number; miss: boolean } | null>(null);
  const [totals, setTotals]       = useState<Record<string, number>>(Object.fromEntries(players.map(p => [p.id, 0])));
  const [gameOver, setGameOver]   = useState(false);
  const [winners, setWinners]     = useState<string[]>([]);

  const isMyTurn = useCallback(() => {
    const s = stateRef.current;
    return !s.gameOver && s.players[s.currentPlayerIndex] === playerId;
  }, [playerId]);

  // ── Event bus ──────────────────────────────────────────────────────────────
  const bus = useMemo(() => new ArcheryEventBus(), []);

  useEffect(() => {
    const onAim = ({ aimNorm }: { aimNorm: Vec2 }) => {
      aimRef.current = aimNorm;
    };
    const onPull = ({ power }: { power: number }) => {
      pullRef.current = power;
      // Update string visual
      if (sceneRef.current) {
        const pts = sceneRef.current.bowString.geometry.attributes.position as THREE.BufferAttribute;
        pts.setXYZ(1, power * BOW_PULL_VISUAL, 0, power * 0.12);
        pts.needsUpdate = true;
        sceneRef.current.arrowOnBow.position.z = -0.35 + power * 0.18;
      }
    };
    const onShoot = ({ aimNorm, power }: { aimNorm: Vec2; power: number }) => {
      if (!isMyTurn()) return;
      // Reset string
      if (sceneRef.current) {
        const pts = sceneRef.current.bowString.geometry.attributes.position as THREE.BufferAttribute;
        pts.setXYZ(1, 0, 0, 0); pts.needsUpdate = true;
        sceneRef.current.arrowOnBow.position.z = -0.35;
        animateArrow(sceneRef.current.scene, aimNorm);
      }
      socket.emit('archery:shoot', { roomId, playerId, aimNorm, power });
      pullRef.current = 0;
    };

    bus.on('archery:aim',   onAim);
    bus.on('archery:pull',  onPull);
    bus.on('archery:shoot', onShoot);
    return () => {
      bus.off('archery:aim',   onAim);
      bus.off('archery:pull',  onPull);
      bus.off('archery:shoot', onShoot);
    };
  }, [bus, isMyTurn, socket, roomId, playerId]);

  // ── Socket events ──────────────────────────────────────────────────────────
  useEffect(() => {
    socket.on('archery:shot', (data: ShotResult) => {
      stateRef.current = data.state;
      setGameState(data.state);
      setLastShot({ ringLabel: data.shot.ringLabel, points: data.shot.points, miss: data.shot.miss });
      setTotals(data.totals);
      // Animate arrow for ALL players (including the shooter — server confirms)
      if (sceneRef.current) {
        animateArrow(sceneRef.current.scene, data.shot.hitNorm, () => {
          if (sceneRef.current) placeHitMarker(sceneRef.current.scene, data.shot.hitNorm);
        });
      }
    });
    socket.on('game:over', (data: { winners: string[]; totals: Record<string, number> }) => {
      setGameOver(true);
      setWinners(data.winners);
      if (data.totals) setTotals(data.totals);
    });
    return () => { socket.off('archery:shot'); socket.off('game:over'); };
  }, [socket]);

  // ── Three.js setup ─────────────────────────────────────────────────────────
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const s = buildScene(canvas);
    sceneRef.current = s;

    const resize = () => {
      const w = canvas.clientWidth, h = canvas.clientHeight;
      s.renderer.setSize(w, h, false);
      s.camera.aspect = w / h;
      s.camera.updateProjectionMatrix();
    };
    resize();
    window.addEventListener('resize', resize);

    let t = 0;
    const animate = () => {
      animFrameRef.current = requestAnimationFrame(animate);
      t += 0.016;

      // Wind particles
      const pos = s.particles.geometry.attributes.position as THREE.BufferAttribute;
      const wind = stateRef.current.wind;
      for (let i = 0; i < PARTICLE_COUNT; i++) {
        pos.array[i*3]   += wind.x * 0.012 + 0.005;
        pos.array[i*3+2] += 0.04;
        if (pos.array[i*3+2] > 2)  pos.array[i*3+2] = -60;
        if (pos.array[i*3]   > 10) pos.array[i*3]   = -10;
      }
      pos.needsUpdate = true;

      // Tree sway
      s.scene.children.forEach(child => {
        if (child instanceof THREE.Mesh && child.geometry instanceof THREE.SphereGeometry) {
          child.rotation.z = Math.sin(t * 0.8 + child.position.x) * 0.03;
        }
      });

      // Tremor
      if (isMyTurn() && ARCHERY_RULES.tremorAmplitude > 0) {
        const amp = ARCHERY_RULES.tremorAmplitude * (1 - pullRef.current * 0.5);
        s.camera.rotation.x = (aimRef.current.y * 0.08) + Math.sin(t * 3.1) * amp * 0.5;
        s.camera.rotation.y = (-aimRef.current.x * 0.08) + Math.sin(t * 2.7 + 1) * amp;
      } else {
        s.camera.rotation.x = 0;
        s.camera.rotation.y = 0;
      }

      // Aim dot
      if (pullRef.current > 0 && isMyTurn()) {
        s.aimDot.visible = true;
        s.aimDot.position.set(aimRef.current.x * TARGET_RADIUS, 1.6 + aimRef.current.y * TARGET_RADIUS, TARGET_Z + 0.15);
        (s.aimDot.material as THREE.MeshBasicMaterial).opacity = 0.5 + pullRef.current * 0.5;
      } else {
        s.aimDot.visible = false;
      }

      s.renderer.render(s.scene, s.camera);
    };
    animate();

    return () => {
      cancelAnimationFrame(animFrameRef.current);
      window.removeEventListener('resize', resize);
      s.renderer.dispose();
    };
  }, [isMyTurn]);

  const currentPlayer = players.find(p => p.id === gameState.players[gameState.currentPlayerIndex]);
  const myTurn = isMyTurn();

  const ctxValue = useMemo(() => ({
    bus,
    getState: () => ({ myTurn: isMyTurn() }),
  }), [bus, isMyTurn]);

  return (
    <ArcheryControllerContext.Provider value={ctxValue}>
      <div className="relative w-full h-full select-none">
        <canvas ref={canvasRef} className="w-full h-full" style={{ touchAction: 'none' }} />

        {/* Controllers */}
        {controller ?? (
          <>
            <ArcheryMouseController canvas={canvasRef.current} />
            <ArcheryTouchController canvas={canvasRef.current} />
          </>
        )}

        {/* HUD — scores */}
        <div className="absolute top-4 left-4 right-4 flex justify-between pointer-events-none">
          <div className="bg-black/60 backdrop-blur rounded-xl px-4 py-2 text-sm">
            <div className="text-slate-400 text-xs mb-1">
              Set {gameState.currentSet}/{ARCHERY_RULES.sets} · Arrow {(gameState.arrowsFiredThisSet % ARCHERY_RULES.arrowsPerSet) + 1}/{ARCHERY_RULES.arrowsPerSet}
            </div>
            {players.map(p => (
              <div key={p.id} className={`flex gap-3 ${p.id === playerId ? 'text-green-400' : 'text-white'}`}>
                <span className="font-bold">{p.username}</span>
                <span>{totals[p.id] ?? 0} pts</span>
              </div>
            ))}
          </div>
          {ARCHERY_RULES.maxWindSpeed > 0 && (
            <div className="bg-black/60 backdrop-blur rounded-xl px-4 py-2 text-xs text-slate-300">
              <div className="text-slate-500 mb-0.5">Wind</div>
              <div>{Math.sqrt(gameState.wind.x**2 + gameState.wind.y**2).toFixed(1)} m/s</div>
              <div style={{ transform: `rotate(${Math.atan2(gameState.wind.y, gameState.wind.x)*180/Math.PI}deg)` }} className="text-lg text-center">→</div>
            </div>
          )}
        </div>

        {/* Turn indicator */}
        <div className="absolute bottom-24 left-1/2 -translate-x-1/2 pointer-events-none">
          {myTurn
            ? <div className="bg-green-900/80 backdrop-blur border border-green-600 rounded-xl px-5 py-2 text-green-300 text-sm font-bold">Your turn — aim &amp; pull to shoot</div>
            : <div className="bg-black/60 backdrop-blur rounded-xl px-5 py-2 text-slate-400 text-sm">{currentPlayer?.username ?? '…'} is shooting…</div>
          }
        </div>

        {/* Last shot */}
        {lastShot && (
          <div className="absolute bottom-40 left-1/2 -translate-x-1/2 pointer-events-none animate-bounce">
            <div className={`rounded-xl px-4 py-2 text-center font-bold text-lg ${lastShot.miss ? 'bg-red-900/80 text-red-300' : 'bg-yellow-900/80 text-yellow-300'}`}>
              {lastShot.miss ? 'MISS' : `${lastShot.ringLabel} · ${lastShot.points} pts`}
            </div>
          </div>
        )}

        {/* Pull power bar */}
        {myTurn && (
          <div className="absolute bottom-8 left-1/2 -translate-x-1/2 w-48 pointer-events-none">
            <div className="text-xs text-slate-400 text-center mb-1">Pull power</div>
            <div className="h-2 bg-slate-800 rounded-full overflow-hidden">
              <div className="h-full bg-green-500 rounded-full transition-none" style={{ width: `${pullRef.current * 100}%` }} />
            </div>
          </div>
        )}

        {/* Game over */}
        {gameOver && (
          <div className="absolute inset-0 bg-black/75 flex items-center justify-center">
            <div className="bg-slate-900 border border-slate-700 rounded-2xl p-8 text-center max-w-sm w-full mx-4">
              <div className="text-5xl mb-4">🏹</div>
              <h2 className="text-2xl font-bold mb-2 text-white">{winners.includes(playerId) ? '🏆 You Win!' : 'Game Over'}</h2>
              <div className="space-y-1 mb-6">
                {[...players].sort((a,b) => (totals[b.id]??0)-(totals[a.id]??0)).map((p,i) => (
                  <div key={p.id} className={`flex justify-between px-3 py-1.5 rounded-lg ${p.id===playerId ? 'bg-green-900/40 text-green-300' : 'text-slate-300'}`}>
                    <span>{i+1}. {p.username}</span>
                    <span className="font-bold">{totals[p.id]??0} pts</span>
                  </div>
                ))}
              </div>
              <button onClick={() => window.location.href='/games/archery'} className="w-full py-3 bg-green-700 hover:bg-green-600 text-white font-bold rounded-lg transition-colors">
                Play Again
              </button>
            </div>
          </div>
        )}
      </div>
    </ArcheryControllerContext.Provider>
  );
}

const BOW_PULL_VISUAL = 0.18;

