/**
 * Shared socket lifecycle hook for all game types.
 * Handles: connect, reconnect, matchmaking join, AFK countdown, game:over.
 * Each game passes its own event handlers for game-specific events.
 */

import { useEffect, useRef } from 'react';
import { io, Socket } from 'socket.io-client';
import { useBetaGamer } from '../../context/BetaGamerProvider';
import { EventBus } from '../../EventBus';

export interface AfkWarning { playerId: string; secondsRemaining: number; }

export interface GameSocketHandlers {
  namespace:        string;
  afkEvent:         string; // e.g. 'checkers:afk_warning'
  afkClearedEvent:  string;
  afkMovePrompt?:   string;
  onGameStarted:    (d: any) => void;
  onMoveMade:       (d: any) => void;
  onGameOver:       (d: any) => void;
  onAfkWarning:     (w: AfkWarning) => void;
  onAfkCleared:     () => void;
  /** Optional extra events: [eventName, handler][] */
  extraEvents?:     [string, (d: any) => void][];
}

export function useGameSocket(handlers: GameSocketHandlers): { socketRef: React.MutableRefObject<Socket | null>; roomIdRef: React.MutableRefObject<string | null>; myPlayerIdRef: React.MutableRefObject<string>; } {
  const { token, serverUrl, socketPath, session, socket: providerSocket, _registerSocket, _updateGameState } = useBetaGamer();
  const myPlayer = session.players[0];

  const socketRef     = useRef<Socket | null>(null);
  const roomIdRef     = useRef<string | null>(null);
  const myPlayerIdRef = useRef<string>(myPlayer?.id ?? '');
  const afkTimerRef   = useRef<ReturnType<typeof setInterval> | null>(null);

  const stopAfkTimer = () => {
    if (afkTimerRef.current) { clearInterval(afkTimerRef.current); afkTimerRef.current = null; }
  };

  useEffect(() => {
    const s: Socket = providerSocket ?? io(`${serverUrl}/${handlers.namespace}`, {
      auth: { token }, path: socketPath, transports: ['websocket', 'polling'],
    });
    socketRef.current = s;
    if (!providerSocket) _registerSocket(s);

    const join = () => s.emit('matchmaking:join', {
      username: myPlayer.displayName, playerId: myPlayer.id,
      wantsBot: session.matchType === 'bot', sessionId: session.sessionId,
    });

    let reconnectFallback: ReturnType<typeof setTimeout> | null = null;

    const tryJoinOrReconnect = () => {
      // Attempt reconnect — if no game:reconnected within 2s, fall through to matchmaking
      reconnectFallback = setTimeout(join, 2000);
      s.once('game:reconnected', () => {
        if (reconnectFallback) { clearTimeout(reconnectFallback); reconnectFallback = null; }
      });
      s.emit('game:reconnect', { playerId: myPlayer.id });
    };

    s.on('connect', tryJoinOrReconnect);
    if (s.connected) tryJoinOrReconnect();

    s.on('game:started', (d: any) => {
      roomIdRef.current = d.roomId;
      myPlayerIdRef.current = d.playerId;
      handlers.onGameStarted(d);
      EventBus.emit('game:started', d);
    });

    // Treat reconnected the same as started — restores state after socket drop
    s.on('game:reconnected', (d: any) => {
      roomIdRef.current = d.roomId;
      myPlayerIdRef.current = d.playerId;
      handlers.onGameStarted(d);
      EventBus.emit('game:started', d);
    });

    s.on('game:move:made', (d: any) => {
      stopAfkTimer();
      handlers.onMoveMade(d);
      EventBus.emit('game:move:made', d);
    });

    s.on(handlers.afkEvent, (d: AfkWarning) => {
      handlers.onAfkWarning(d);
      EventBus.emit(handlers.afkEvent as any, d);
      stopAfkTimer();
      afkTimerRef.current = setInterval(() => {
        handlers.onAfkWarning({ ...d, secondsRemaining: 0 }); // trigger re-render via parent
        // Parent manages countdown state; we just tick
      }, 1000);
    });

    s.on(handlers.afkClearedEvent, () => {
      stopAfkTimer();
      handlers.onAfkCleared();
      EventBus.emit(handlers.afkClearedEvent as any, undefined);
    });

    s.on('afk:status', (status: { playerId: string; expiresAt: number } | null) => {
      if (!status) { stopAfkTimer(); handlers.onAfkCleared(); }
      else handlers.onAfkWarning({ playerId: status.playerId, secondsRemaining: Math.max(1, Math.round((status.expiresAt - Date.now()) / 1000)) });
      EventBus.emit('afk:status', status);
    });

    s.on('game:over', (d: any) => {
      _updateGameState({ status: 'ended', winner: d.winner ?? null, reason: d.reason });
      handlers.onGameOver(d);
      EventBus.emit('game:over', { winner: d.winner ?? null, reason: d.reason });
    });

    handlers.extraEvents?.forEach(([event, handler]) => s.on(event, handler));

    return () => {
      stopAfkTimer();
      if (reconnectFallback) clearTimeout(reconnectFallback);
      s.off('connect', tryJoinOrReconnect);
      if (!providerSocket) s.disconnect();
      socketRef.current = null;
    };
  }, [token, serverUrl, socketPath]);

  return { socketRef, roomIdRef, myPlayerIdRef };
}

