import { useEffect, useRef, useState } from 'react';
import type { Socket } from 'socket.io-client';
import { useBetaGamer } from '@beta-gamer/react';

interface Piece { player: 'red' | 'black'; type: 'man' | 'king'; }
interface Move  { from: number; to: number; captures?: number[]; }

export interface CheckersGameState {
  socket:        Socket | null;
  roomId:        string | null;
  myPlayerId:    string;
  myColor:       'red' | 'black';
  board:         Array<Piece | null>;
  currentTurn:   number;
  players:       any[];
  selectedPiece: number | null;
  validMoves:    Move[];
  lastMove:      { from: number; to: number } | null;
  gameOver:      boolean;
  gameResult:    { winner: string | null; reason: string } | null;
  afkWarning:    { playerId: string; secondsRemaining: number } | null;
  isMyTurn:      boolean;
  handleCellClick: (pos: number) => void;
}

export interface CheckersGameCallbacks {
  onGameStarted?: (data: { myColor: 'red' | 'black'; players: any[] }) => void;
  onMove?:        (data: { from: number; to: number; byMe: boolean }) => void;
  onCapture?:     (data: { captured: number[]; byMe: boolean }) => void;
  onCrowned?:     (data: { square: number; byMe: boolean }) => void;
  onGameOver?:    (data: { winner: string | null; reason: string }) => void;
  onAfkWarning?:  (data: { playerId: string; secondsRemaining: number; isMe: boolean }) => void;
}

export function useCheckersGame(callbacks: CheckersGameCallbacks = {}): CheckersGameState {
  const { session, socket } = useBetaGamer();
  const myPlayer = session.players[0];
  const cbRef = useRef(callbacks);
  cbRef.current = callbacks;

  const roomIdRef     = useRef<string | null>(null);
