import React, { useState } from 'react';
import { View, Text, TouchableOpacity, StyleSheet, Dimensions, ViewStyle } from 'react-native';
import { Socket } from 'socket.io-client';
import { useGameSocket } from '@beta-gamer/react-native-ui';
import { GameOverModal, PlayerRow, AfkBanner, ActionButtons, sharedStyles as ss, lastMoveOverlayStyle } from '@beta-gamer/react-native-ui';
import type { LastMoveStyle, AfkWarning } from '@beta-gamer/react-native-ui';

interface Move  { from: number; to: number; captures?: number[]; }
interface Piece { player: 'red' | 'black'; type: 'man' | 'king'; }

export interface CheckersGameState {
  socket:          Socket | null;
  roomId:          string | null;
  myPlayerId:      string;
  myColor:         'red' | 'black';
  board:           Array<Piece | null>;
  currentTurn:     number;
  players:         Array<{ id: string; displayName: string }>;
  selectedPiece:   number | null;
  validMoves:      Move[];
  lastMove:        { from: number; to: number } | null;
  gameOver:        boolean;
  gameResult:      { winner: string | null; reason: string } | null;
  afkWarning:      AfkWarning | null;
  isMyTurn:        boolean;
  handleCellPress: (pos: number) => void;
}

export function useCheckersGame(): CheckersGameState {
  const [board, setBoard]             = useState<Array<Piece | null>>(Array(64).fill(null));
  const [myColor, setMyColor]         = useState<'red' | 'black'>('red');
  const [currentTurn, setCurrentTurn] = useState(0);
  const [players, setPlayers]         = useState<Array<{ id: string; displayName: string }>>([]);
  const [selectedPiece, setSelectedPiece] = useState<number | null>(null);
  const [validMoves, setValidMoves]   = useState<Move[]>([]);
  const [lastMove, setLastMove]       = useState<{ from: number; to: number } | null>(null);
  const [gameOver, setGameOver]       = useState(false);
  const [gameResult, setGameResult]   = useState<{ winner: string | null; reason: string } | null>(null);
  const [afkWarning, setAfkWarning]   = useState<AfkWarning | null>(null);

  const { socketRef, roomIdRef, myPlayerIdRef } = useGameSocket({
    namespace:       'checkers',
    afkEvent:        'checkers:afk_warning',
    afkClearedEvent: 'checkers:afk_warning_cleared',
    onGameStarted: (d) => { setMyColor(d.color ?? 'red'); setBoard(d.board ?? Array(64).fill(null)); setCurrentTurn(d.currentTurn ?? 0); setPlayers(d.players ?? []); },
    onMoveMade:    (d) => { setBoard(d.board); setCurrentTurn(d.currentTurn ?? 0); setSelectedPiece(null); setValidMoves([]); if (d.move) setLastMove({ from: d.move.from, to: d.move.to }); setAfkWarning(null); },
    onGameOver:    (d) => { setGameResult({ winner: d.winner ?? null, reason: d.reason }); setTimeout(() => setGameOver(true), 400); },
    onAfkWarning:  (w) => setAfkWarning(w),
    onAfkCleared:  ()  => setAfkWarning(null),
    extraEvents:   [['game:valid_moves', (d: { position: number; moves: Move[] }) => { setSelectedPiece(d.position); setValidMoves(d.moves); }]],
  });

  const isMyTurn = players.length > 0 ? players[currentTurn]?.id === myPlayerIdRef.current : false;

  const handleCellPress = (pos: number) => {
    if (!isMyTurn || !socketRef.current) return;
    if (selectedPiece === null) {
      const piece = board[pos];
      if (piece && piece.player === myColor) {
        socketRef.current.emit('checkers:select', { roomId: roomIdRef.current, playerId: myPlayerIdRef.current, position: pos });
      }
    } else {
      const move = validMoves.find(m => m.to === pos);
      if (move) {
        socketRef.current.emit('checkers:move', { roomId: roomIdRef.current, playerId: myPlayerIdRef.current, move });
        setSelectedPiece(null);
        setValidMoves([]);
      } else {
        setSelectedPiece(null);
        setValidMoves([]);
      }
    }
  };

  return {
    socket: socketRef.current,
    roomId: roomIdRef.current,
    myPlayerId: myPlayerIdRef.current,
    myColor,
    board,
    currentTurn,
    players,
    selectedPiece,
    validMoves,
    lastMove,
    gameOver,
    gameResult,
    afkWarning,
    isMyTurn,
    handleCellPress,
  };
}

interface BoardStyles {
  darkSquare?:  ViewStyle;
  lightSquare?: ViewStyle;
  redPiece?:    ViewStyle;
  blackPiece?:  ViewStyle;
  kingPiece?:   ViewStyle;
}

interface Props {
  style?:          ViewStyle;
  layout?:         'default' | 'board-only';
  showAfkWarning?: boolean;
  showLastMove?:   boolean;
  showGameOver?:   boolean;
  lastMoveStyle?:  LastMoveStyle;
  game?:           ReturnType<typeof useCheckersGame>;
  onLeave?:        () => void;
  boardStyles?:    BoardStyles;
}

export function CheckersBoard({ style, layout = 'board-only', showAfkWarning = true, showLastMove = true, showGameOver = true, lastMoveStyle = 'glow', game: gameProp, onLeave, boardStyles = {} }: Props) {
  const gameInternal = useCheckersGame();
  const game = gameProp ?? gameInternal;
  const { myColor, board, selectedPiece, validMoves, lastMove, gameOver, gameResult, afkWarning, isMyTurn, handleCellPress } = game;

  const renderSquare = (pos: number) => {
    const row = Math.floor(pos / 8);
    const col = pos % 8;
    const isDark = (row + col) % 2 === 1;
    const piece = board[pos];
    const isSelected = selectedPiece === pos;
    const isValidMove = validMoves.some(m => m.to === pos);
    const isLastMove = showLastMove && lastMove && (lastMove.from === pos || lastMove.to === pos);

    return (
      <TouchableOpacity
        key={pos}
        style={[
          styles.square,
          isDark ? [styles.darkSquare, boardStyles.darkSquare] : [styles.lightSquare, boardStyles.lightSquare],
          isSelected && styles.selectedSquare,
          isValidMove && styles.validMoveSquare,
          isLastMove && lastMoveOverlayStyle(lastMoveStyle),
        ]}
        onPress={() => handleCellPress(pos)}
        disabled={!isMyTurn}
      >
        {piece && (
          <View style={[
            styles.piece,
            piece.player === 'red' ? [styles.redPiece, boardStyles.redPiece] : [styles.blackPiece, boardStyles.blackPiece],
            piece.type === 'king' && [styles.kingPiece, boardStyles.kingPiece],
          ]}>
            {piece.type === 'king' && <Text style={styles.crownText}>♔</Text>}
          </View>
        )}
      </TouchableOpacity>
    );
  };

  if (layout === 'board-only') {
    return (
      <View style={[styles.container, style]}>
        <View style={styles.board}>
          {Array.from({ length: 64 }, (_, i) => renderSquare(i))}
        </View>
        {showAfkWarning && afkWarning && <AfkBanner warning={afkWarning} />}
        {showGameOver && gameOver && gameResult && (
          <GameOverModal
            visible={gameOver}
            winner={gameResult.winner}
            reason={gameResult.reason}
            onPlayAgain={() => {}}
            onLeave={onLeave}
          />
        )}
      </View>
    );
  }

  return (
    <View style={[ss.gameContainer, style]}>
      <View style={ss.playersContainer}>
        {game.players.map((player, i) => (
          <PlayerRow
            key={player.id}
            player={player}
            isCurrentTurn={i === game.currentTurn}
            isMe={player.id === game.myPlayerId}
          />
        ))}
      </View>
      <View style={styles.board}>
        {Array.from({ length: 64 }, (_, i) => renderSquare(i))}
      </View>
      <ActionButtons onLeave={onLeave} />
      {showAfkWarning && afkWarning && <AfkBanner warning={afkWarning} />}
      {showGameOver && gameOver && gameResult && (
        <GameOverModal
          visible={gameOver}
          winner={gameResult.winner}
          reason={gameResult.reason}
          onPlayAgain={() => {}}
          onLeave={onLeave}
        />
      )}
    </View>
  );
}

const { width } = Dimensions.get('window');
const boardSize = Math.min(width * 0.9, 400);
const squareSize = boardSize / 8;

const styles = StyleSheet.create({
  container: {
    alignItems: 'center',
    justifyContent: 'center',
  },
  board: {
    width: boardSize,
    height: boardSize,
    flexDirection: 'row',
    flexWrap: 'wrap',
    borderWidth: 2,
    borderColor: '#8B4513',
  },
  square: {
    width: squareSize,
    height: squareSize,
    alignItems: 'center',
    justifyContent: 'center',
  },
  darkSquare: {
    backgroundColor: '#8B4513',
  },
  lightSquare: {
    backgroundColor: '#DEB887',
  },
  selectedSquare: {
    backgroundColor: '#FFD700',
  },
  validMoveSquare: {
    backgroundColor: '#90EE90',
  },
  piece: {
    width: squareSize * 0.8,
    height: squareSize * 0.8,
    borderRadius: squareSize * 0.4,
    alignItems: 'center',
    justifyContent: 'center',
    borderWidth: 2,
  },
  redPiece: {
    backgroundColor: '#DC143C',
    borderColor: '#8B0000',
  },
  blackPiece: {
    backgroundColor: '#2F4F4F',
    borderColor: '#000000',
  },
  kingPiece: {
    borderWidth: 3,
    borderColor: '#FFD700',
  },
  crownText: {
    color: '#FFD700',
    fontSize: squareSize * 0.4,
    fontWeight: 'bold',
  },
});

