'use client';

import { useState } from 'react';
import { useRouter } from 'next/navigation';
import Link from 'next/link';

export default function CheckersSDKPage() {
  const router = useRouter();
  const [username, setUsername] = useState('');
  const [mode, setMode] = useState<'matchmaking' | 'bot'>('matchmaking');
  const [difficulty, setDifficulty] = useState<'easy' | 'medium' | 'hard'>('medium');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handlePlay = async () => {
    if (!username.trim()) return;
    setLoading(true);
    setError('');
    try {
      const res = await fetch('/api/v1/sessions', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${(window as any).__BG_TEST_KEY__ || 'bg_test_a662905f74959d4c32f30dc6f97d58573621ba2a1fa30eeb'}`,
        },
        body: JSON.stringify({
          game: 'checkers',
          mode: 'test',
          matchType: mode === 'bot' ? 'bot' : 'matchmaking',
          players: [{ id: `user_${Date.now()}`, displayName: username }],
          botDifficulty: difficulty,
        }),
      });
      if (!res.ok) { const e = await res.json(); throw new Error(e.error || 'Failed to create session'); }
      const { sessionId, sessionToken } = await res.json();
      router.push(`/sdk-games/checkers/${sessionId}?token=${sessionToken}&difficulty=${difficulty}&mode=${mode}`);
    } catch (e: any) {
      setError(e.message);
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-[#0a0a0f] text-white flex flex-col">
      <div className="border-b border-slate-800 px-6 py-4 flex items-center gap-4">
        <Link href="/sdk-games" className="text-slate-400 hover:text-white text-sm transition-colors">← Games</Link>
        <span className="text-slate-600">|</span>
        <span className="text-white font-semibold">⬤ Checkers</span>
        <span className="ml-2 text-xs bg-red-900/40 text-red-300 border border-red-700/40 px-2 py-0.5 rounded-full">SDK demo</span>
      </div>

      <div className="flex-1 flex items-center justify-center px-4">
        <div className="w-full max-w-sm">
          <div className="text-center mb-8">
            <div className="text-6xl mb-4">⬤</div>
            <h1 className="text-3xl font-bold mb-2">Checkers</h1>
            <p className="text-slate-400 text-sm">Powered by <code className="text-red-300">@beta-gamer/react</code></p>
          </div>

          <div className="bg-slate-900 border border-slate-800 rounded-2xl p-6 space-y-4">
            <div>
              <label className="block text-xs text-slate-400 mb-1.5">Your name</label>
              <input
                value={username}
                onChange={e => setUsername(e.target.value)}
                onKeyDown={e => e.key === 'Enter' && handlePlay()}
                placeholder="Enter your name"
