import { useState } from 'react';
import { useRouter } from 'next/navigation';
import Link from 'next/link';

export default function CheckersSDKPage() {
  const router = useRouter();
  const [username, setUsername] = useState('');
  const [mode, setMode] = useState<'matchmaking' | 'bot'>('matchmaking');
  const [difficulty, setDifficulty] = useState<'easy' | 'medium' | 'hard'>('medium');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handlePlay = async () => {
    if (!username.trim()) return;
    setLoading(true);
    setError('');
    try {
      const res = await fetch('/api/v1/sessions', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${(window as any).__BG_TEST_KEY__ || 'bg_test_a662905f74959d4c32f30dc6f97d58573621ba2a1fa30eeb'}`,
        },
        body: JSON.stringify({
          game: 'checkers',
          mode: 'test',
          matchType: mode === 'bot' ? 'bot' : 'matchmaking',
          players: [{ id: `user_${Date.now()}`, displayName: username }],
          botDifficulty: difficulty,
        }),
      });
      if (!res.ok) { const e = await res.json(); throw new Error(e.error || 'Failed to create session'); }
      const { sessionId, sessionToken } = await res.json();
      router.push(`/sdk-games/checkers/${sessionId}?token=${sessionToken}&difficulty=${difficulty}&mode=${mode}`);
    } catch (e: any) {
      setError(e.message);
      setLoading(false);
