'use client';

import { useParams, useSearchParams, useRouter } from 'next/navigation';
import { Suspense, useEffect, useState } from 'react';
import { BetaGamerProvider } from '@beta-gamer/react';
import { CheckersSDKRoom } from '@/components/games/checkers/CheckersSDKRoom';
import Link from 'next/link';

function CheckersSDKPageInner() {
  const { sessionId } = useParams<{ sessionId: string }>();
  const searchParams = useSearchParams();
  const token = searchParams.get('token');
  const difficulty = (searchParams.get('difficulty') || 'medium') as 'easy' | 'medium' | 'hard';
  const matchType = (searchParams.get('mode') || 'bot') as 'bot' | 'matchmaking';
  const router = useRouter();

  const [sessionStatus, setSessionStatus] = useState<'checking' | 'ok' | 'ended' | 'invalid'>('checking');

  useEffect(() => {
    if (!token) { setSessionStatus('invalid'); return; }
    fetch(`/api/v1/sessions/validate?token=${token}`)
      .then(r => r.json())
      .then(d => {
        if (d.status === 'ended') {
          setSessionStatus('ended');
        } else {
          // pending or active — clear any stale game-over data then render game
          sessionStorage.removeItem(`bg_ended_${sessionId}`);
          setSessionStatus('ok');
        }
      })
      .catch(() => setSessionStatus('ok'));
  }, [token]);

  if (!token || sessionStatus === 'invalid') return (
    <div className="min-h-screen bg-[#0a0a0f] flex items-center justify-center text-white">
      <div className="text-center">
        <p className="text-slate-400 mb-4">No session token found.</p>
        <Link href="/sdk-games/checkers" className="text-red-400 hover:underline text-sm">← Back to lobby</Link>
      </div>
    </div>
  );

  if (sessionStatus === 'checking') return (
    <div className="min-h-screen bg-[#0a0a0f] flex items-center justify-center">
      <div className="w-10 h-10 border-2 border-red-500 border-t-transparent rounded-full animate-spin" />
    </div>
  );

  if (sessionStatus === 'ended') return (
    <div className="min-h-screen bg-[#0a0a0f] flex items-center justify-center text-white">
      <div className="text-center space-y-3">
        <div className="text-4xl">🏁</div>
        <p className="text-white font-semibold">This session has already ended.</p>
        <p className="text-slate-400 text-sm">Session tokens are single-use and cannot be replayed.</p>
        <Link href="/sdk-games/checkers" className="inline-block mt-4 text-red-400 hover:underline text-sm">← Play a new game</Link>
      </div>
    </div>
  );

  return (
    <BetaGamerProvider
      token={token}
      serverUrl={window.location.origin}
      socketPath="/api/socket/io"
    >
      <CheckersSDKRoom
        sessionId={sessionId}
        difficulty={difficulty}
        matchType={matchType}
        onLeave={() => router.push('/sdk-games/checkers')}
      />
    </BetaGamerProvider>
  );
}

export default function CheckersSDKSessionPage() {
  return (
    <Suspense fallback={
      <div className="min-h-screen bg-[#0a0a0f] flex items-center justify-center">
        <div className="w-10 h-10 border-2 border-red-500 border-t-transparent rounded-full animate-spin" />
      </div>
    }>
      <CheckersSDKPageInner />
    </Suspense>
  );
}

