'use client';

import { useEffect, useState, useCallback, useRef } from 'react';
import { useSession, useSocket } from '@beta-gamer/react';
import { CheckersBoard } from './CheckersBoard';
import Link from 'next/link';

interface Piece { player: 'red' | 'black'; type: 'man' | 'king'; }
interface Move { from: number; to: number; captures?: number[]; }

interface Props {
  sessionId: string;
  difficulty: 'easy' | 'medium' | 'hard';
  matchType: 'bot' | 'matchmaking';
  onLeave: () => void;
  showAfkWarning?: boolean;
  showLastMove?: boolean;
  orientationOverride?: 'red' | 'black' | null;
}

export function CheckersSDKRoom({ sessionId, difficulty, matchType, onLeave, showAfkWarning = true, showLastMove = true, orientationOverride = null }: Props) {
  const socket = useSocket();
  const session = useSession();
  const myPlayer = session.players[0];

  // Player ID comes exclusively from the JWT — tenant-issued, reflects whoever
  // the current token was created for. Never fall back to sessionStorage for
  // identity: if the user signs out and a different account loads the page,
  // their token has a different id and the result screen is irrelevant to them.
  const tokenPlayerId = myPlayer?.id ?? '';

  const [roomId, setRoomId] = useState<string | null>(null);
  const [myPlayerId, setMyPlayerId] = useState(tokenPlayerId);
  const [myColor, setMyColor] = useState<'red' | 'black'>('red');
  const [board, setBoard] = useState<Array<Piece | null>>(Array(64).fill(null));
  const [currentTurn, setCurrentTurn] = useState<number>(0);
  const [selectedPiece, setSelectedPiece] = useState<number | null>(null);
  const [validMoves, setValidMoves] = useState<Move[]>([]);
  const [moveHistory, setMoveHistory] = useState<Move[]>([]);
  const [opponentName, setOpponentName] = useState('Waiting…');
  const [gameOver, setGameOver] = useState(false);
  const [gameResult, setGameResult] = useState<{ winner: string | null; reason: string } | null>(() => {
    if (typeof window === 'undefined') return null;
    const stored = sessionStorage.getItem(`bg_ended_${sessionId}`);
    return stored ? JSON.parse(stored) : null;
  });
  const [overlayDismissed, setOverlayDismissed] = useState(false);
  const [afkWarning, setAfkWarning] = useState<{ playerId: string; secondsRemaining: number } | null>(null);
  const afkCountdownRef = useRef<ReturnType<typeof setInterval> | null>(null);
  const roomIdRef = useRef<string | null>(null);

  const isMyTurn = useCallback((turn: number, color: string, players: any[]) => {
    if (!players.length) return false;
    // currentTurn is the index into room.players — check if that player is me
    return players[turn]?.id === myPlayerId || color === (turn === 0 ? 'red' : 'black');
  }, [myPlayerId]);

  // Derived: is it my turn right now?
  const myTurn = myPlayerId
    ? (currentTurn === 0 ? myColor === 'red' : myColor === 'black')
    : false;

  // Show result overlay if session already ended (e.g. page refresh after game over)
  useEffect(() => {
    if (sessionStorage.getItem(`bg_ended_${sessionId}`)) setGameOver(true);
  }, []);

  useEffect(() => {
    if (!socket || gameResult) return;

    const join = () => socket.emit('matchmaking:join', {
      username: myPlayer.displayName,
      playerId: tokenPlayerId,
      wantsBot: matchType === 'bot',
      botDifficulty: difficulty,
      sessionId,
    });

    if (socket.connected) join();
    else socket.once('connect', join);

    socket.on('game:started', (d: any) => {
      setRoomId(d.roomId);
      roomIdRef.current = d.roomId;
      setMyPlayerId(d.playerId);
      setMyColor(d.color);
      setBoard(d.board);
      setCurrentTurn(d.currentTurn ?? 0);
      const opp = (d.players as any[]).find((p: any) => p.id !== d.playerId);
      if (opp) setOpponentName(opp.username);
    });

    socket.on('game:move:made', (d: any) => {
      setBoard(d.board);
      setCurrentTurn(d.currentTurn ?? 0);
      setMoveHistory(d.moveHistory ?? []);
      setSelectedPiece(null);
      setValidMoves([]);
      setAfkWarning(null);
      if (afkCountdownRef.current) { clearInterval(afkCountdownRef.current); afkCountdownRef.current = null; }
    });

    socket.on('checkers:afk_warning', (d: { playerId: string; secondsRemaining: number }) => {
      setAfkWarning(d);
      if (afkCountdownRef.current) clearInterval(afkCountdownRef.current);
      afkCountdownRef.current = setInterval(() => {
        setAfkWarning(prev => {
          if (!prev || prev.secondsRemaining <= 1) {
            clearInterval(afkCountdownRef.current!);
            afkCountdownRef.current = null;
            if (roomIdRef.current) socket.emit('afk:check', { roomId: roomIdRef.current });
            return prev;
          }
          return { ...prev, secondsRemaining: prev.secondsRemaining - 1 };
        });
      }, 1000);
    });

    socket.on('checkers:afk_warning_cleared', () => {
      if (afkCountdownRef.current) { clearInterval(afkCountdownRef.current); afkCountdownRef.current = null; }
      setAfkWarning(null);
    });

    socket.on('afk:status', (status: { playerId: string; expiresAt: number } | null) => {
      if (!status) {
        if (afkCountdownRef.current) { clearInterval(afkCountdownRef.current); afkCountdownRef.current = null; }
        setAfkWarning(null);
      } else {
        const secondsRemaining = Math.max(1, Math.round((status.expiresAt - Date.now()) / 1000));
        setAfkWarning({ playerId: status.playerId, secondsRemaining });
      }
    });

    socket.on('game:valid_moves', (d: { position: number; moves: Move[] }) => {
      setSelectedPiece(d.position);
      setValidMoves(d.moves);
    });

    socket.on('game:over', (d: { winner?: string; reason: string }) => {
      const result = { winner: d.winner ?? null, reason: d.reason };
      sessionStorage.setItem(`bg_ended_${sessionId}`, JSON.stringify(result));
      setGameResult(result);
      setTimeout(() => setGameOver(true), 400);
    });

    return () => {
      socket.off('connect', join);
      socket.off('game:started');
      socket.off('game:move:made');
      socket.off('checkers:afk_warning');
      socket.off('checkers:afk_warning_cleared');
      socket.off('afk:status');
      socket.off('game:valid_moves');
      socket.off('game:over');
      if (afkCountdownRef.current) clearInterval(afkCountdownRef.current);
    };
  }, [socket, myPlayer.displayName, matchType, difficulty]);

  const handleCellClick = (position: number) => {
    if (!socket || !roomId || !myPlayerId || gameOver || !myTurn) return;

    // If a valid move destination is clicked, execute the move
    const move = validMoves.find(m => m.to === position);
    if (move) {
      socket.emit('game:move', { roomId, playerId: myPlayerId, move });
      setSelectedPiece(null);
      setValidMoves([]);
      return;
    }

    // Otherwise request valid moves for this piece
    const piece = board[position];
    if (piece && piece.player === myColor) {
      socket.emit('game:get_moves', { roomId, position, playerId: myPlayerId });
    } else {
      setSelectedPiece(null);
      setValidMoves([]);
    }
  };

  const pieceCount = (color: 'red' | 'black') =>
    board.filter(p => p?.player === color).length;

  return (
    <div className="min-h-screen bg-[#0a0a0f] text-white flex flex-col">
      {/* Nav */}
      <div className="border-b border-slate-800 px-6 py-3 flex items-center gap-3">
        <button onClick={onLeave} className="text-slate-400 hover:text-white text-sm transition-colors">← Leave</button>
        <span className="text-slate-600">|</span>
        <span className="text-slate-400 text-xs font-mono">{sessionId.slice(0, 8)}…</span>
        <span className="ml-auto text-xs bg-red-900/40 text-red-300 border border-red-700/40 px-2 py-0.5 rounded-full">
          @beta-gamer/react
        </span>
      </div>

      <div className="flex-1 flex items-start justify-center gap-6 p-6 max-w-5xl mx-auto w-full">
        {/* Board column */}
        <div className="flex flex-col gap-3 flex-1 max-w-[520px]">
          {/* Opponent row */}
          <div className="flex items-center justify-between bg-slate-900 border border-slate-800 rounded-xl px-4 py-3">
            <div className="flex items-center gap-3">
              <div className="w-8 h-8 rounded-full bg-slate-700 flex items-center justify-center text-sm font-bold">
                {opponentName[0].toUpperCase()}
              </div>
              <div>
                <div className="text-sm font-semibold">{opponentName}</div>
                <div className="text-xs text-slate-500 capitalize">{myColor === 'red' ? 'Black' : 'Red'}</div>
              </div>
            </div>
            <div className="text-sm text-slate-400">
              {pieceCount(myColor === 'red' ? 'black' : 'red')} pieces
            </div>
          </div>

          {/* Turn indicator */}
          <div className={`text-center text-xs font-semibold py-1.5 rounded-lg ${
            myTurn && !gameOver
              ? 'bg-green-900/40 border border-green-700/50 text-green-300'
              : 'bg-slate-800/60 border border-slate-700 text-slate-500'
          }`}>
            {gameOver ? 'Game over' : myTurn ? 'Your turn' : `${opponentName}'s turn`}
          </div>

          {/* AFK warning banner */}
          {showAfkWarning && afkWarning && (
            <div className={`rounded-xl px-4 py-2.5 text-sm font-semibold flex items-center justify-between ${
              afkWarning.playerId === myPlayerId
                ? 'bg-red-900/60 border border-red-600 text-red-200'
                : 'bg-yellow-900/40 border border-yellow-700 text-yellow-300'
            }`}>
              <span>{afkWarning.playerId === myPlayerId ? '⚠️ You are AFK — make a move!' : '⏳ Opponent is AFK'}</span>
              <span className="font-mono tabular-nums">{afkWarning.secondsRemaining}s</span>
            </div>
          )}

          {/* Board */}
          <CheckersBoard
            board={board}
            onCellClick={handleCellClick}
            selectedPiece={selectedPiece}
            validMoves={validMoves}
            isMyTurn={myTurn && !gameOver}
            gameOver={gameOver}
