interface Piece {
  player: 'red' | 'black';
  type: 'man' | 'king';
}

interface Move {
  from: number;
  to: number;
  captures?: number[];
}

interface CheckersBoardProps {
  board: Array<Piece | null>;
  onCellClick: (position: number) => void;
  selectedPiece: number | null;
  validMoves: Move[];
  isMyTurn: boolean;
  gameOver: boolean;
  orientation: 'red' | 'black';
  showLastMove?: boolean;
}

export function CheckersBoard({
  board,
  onCellClick,
  selectedPiece,
  validMoves,
  isMyTurn,
  gameOver,
  orientation,
  showLastMove = true,
}: CheckersBoardProps) {
  const renderCell = (position: number, row: number, col: number) => {
    const piece = board[position];
    const isLight = (row + col) % 2 === 0;
    const isSelected = selectedPiece === position;
    const isValidMove = validMoves.some(m => m.to === position);
    const isCapture = validMoves.find(m => m.to === position)?.captures?.length || 0;

    // Only clickable dark squares
    if (isLight) {
      return (
        <div
          key={position}
          className="aspect-square bg-amber-100"
        />
      );
    }

